export const searchIndex: SearchEntry[] = [{"title":"app","pageTitle":"app","breadcrumb":"app","url":"/app/","content":"The Apps To make Tag and Tally easier there are several tools that can help you.","description":"","headingLevel":1,"fileSlug":"app"},{"title":"Obsidian Vault","pageTitle":"app","breadcrumb":"app › Obsidian Vault","url":"/app/#obsidian-vault","content":"If you use Obsidian.md, you can download a vault, with the markdown files for the game installed, a plugin with the forge tool built in, the rules are also in a pretty format, and several commands that can be helpful. You can download the vault from Google Drive.","description":"","headingLevel":2,"fileSlug":"app"},{"title":"The Forge Web App","pageTitle":"app","breadcrumb":"app › The Forge Web App","url":"/app/#the-forge-web-app","content":"If you don't want to use Obsidian.md, there is a web app that you can install to your desktop or your mobile device and it will work on and offline. You can visit the forge at https://forge.tagandtally.quest","description":"","headingLevel":2,"fileSlug":"app"},{"title":"The Tag and Tally Discord Bot","pageTitle":"app","breadcrumb":"app › The Tag and Tally Discord Bot","url":"/app/#the-tag-and-tally-discord-bot","content":"If your group plays on Discord, you can invite the Tag and Tally bot to your server to roll dice, run resolutions, generate scenes and NPCs, and roll on random tables right in chat. Invite the bot. The bot responds to slash commands — type / in any channel where the bot has access and pick from the list. Available commands include /roll for dice, /resolve for the oracle, /sentence for NPCs and scenes, and /table for any of the random tables in the SRD.","description":"","headingLevel":2,"fileSlug":"app"},{"title":"The Tag and Tally SRD","pageTitle":"app","breadcrumb":"app › The Tag and Tally SRD","url":"/app/#the-tag-and-tally-srd","content":"The docs are also available online and offline on the web at https://tageandtally.quest.","description":"","headingLevel":2,"fileSlug":"app"},{"title":"abilities","pageTitle":"abilities","breadcrumb":"abilities","url":"/generators/tarot/abilities/","content":"","description":"","headingLevel":1,"fileSlug":"abilities"},{"title":"**Major Arcana: Innate Abilities**","pageTitle":"abilities","breadcrumb":"abilities › **Major Arcana: Innate Abilities**","url":"/generators/tarot/abilities/#major-arcana-innate-abilities","content":"0 The Fool - Upright: Uncanny Luck. Frequently avoids disaster through pure, inexplicable coincidence. - Reversed: Fearlessness. A total lack of a self-preservation instinct; immune to \"Fear\" effects. I The Magician - Upright: Perfect Mimicry. The innate talent to copy any voice, sound, or gesture perfectly. - Reversed: Reality Warping. Small, strange coincidences happen around them that defy logic. II The High Priestess - Upright: Second Sight. Periodic, uncontrollable flashes of the immediate future. - Reversed: Aura Reading. The ability to see a person’s true nature as a color or feeling. III The Empress - Upright: Natural Growth. Plants and animals thrive and calm down in their presence. - Reversed: Fertility/Creation. An innate ability to bring ideas or life into the world with ease. IV The Emperor - Upright: Voice of Command. A natural frequency in their voice that compels people to stop and listen. - Reversed: Iron Will. An internal \"lock\" that makes them immune to mental manipu","description":"","headingLevel":2,"fileSlug":"abilities"},{"title":"**Suit of Cups: Abilities of Fluidity and Soul**","pageTitle":"abilities","breadcrumb":"abilities › **Suit of Cups: Abilities of Fluidity and Soul**","url":"/generators/tarot/abilities/#suit-of-cups-abilities-of-fluidity-and-soul","content":"Ace of Cups - Upright: Pure Vessel. Their body naturally filters out mild toxins or poisons in food. - Reversed: Overflow. Their emotions are so \"loud\" they can accidentally influence the mood of others. Two of Cups - Upright: Empathic Link. Can sense the location and status of one \"bonded\" person at all times. - Reversed: Mirroring. Automatically adopts the accent or mannerisms of whoever they talk to. Three of Cups - Upright: Shared Joy. When they are happy, everyone within 10 feet gains a small luck bonus. - Reversed: Social Scent. Can \"smell\" a lie or a hidden motive like a physical odor. Four of Cups - Upright: Mental Fortress. An innate \"boredom\" that makes them immune to most charms. - Reversed: Deep Diver. Can hold their breath for a supernatural amount of time. Five of Cups - Upright: Sorrow-Sense. Can see \"ghosts\" or echoes of past tragedies in a room. - Reversed: Emotional Scavenger. Heals slightly when they witness a powerful emotional event. Six of Cups - Upright: Youthful","description":"","headingLevel":2,"fileSlug":"abilities"},{"title":"**Suit of Cups: Abilities of the Deep Soul**","pageTitle":"abilities","breadcrumb":"abilities › **Suit of Cups: Abilities of the Deep Soul**","url":"/generators/tarot/abilities/#suit-of-cups-abilities-of-the-deep-soul","content":"Page of Cups - Upright: Serendipity. Small, helpful \"coincidences\" happen more frequently when they are in a good mood. - Reversed: Fluid Form. Naturally more resistant to crushing or falling damage; their body \"gives\" like water. Knight of Cups - Upright: Pure Heart. Can sense the \"moral alignment\" or true intent of anyone they break bread with. - Reversed: Mirage. Can subtly alter how they appear to others based on what that person wants to see. Queen of Cups - Upright: Empathic Healing. Can \"absorb\" the pain or status effects of an ally into themselves. - Reversed: Tides. Their power/luck waxes and wanes with the literal phases of the moon. King of Cups - Upright: Emotional Anchor. Prevents all nearby allies from being affected by confusion or madness. - Reversed: Still Waters. Can remain perfectly \"unreadable\" to any form of truth-seeking or mind-reading.","description":"","headingLevel":2,"fileSlug":"abilities"},{"title":"**Suit of Pentacles: Abilities of Earth and Body**","pageTitle":"abilities","breadcrumb":"abilities › **Suit of Pentacles: Abilities of Earth and Body**","url":"/generators/tarot/abilities/#suit-of-pentacles-abilities-of-earth-and-body","content":"Ace of Pentacles - Upright: Golden Touch. Can feel the purity or \"value\" of a material just by touch. - Reversed: Rooted. Gains physical strength as long as they are touching natural earth. Two of Pentacles - Upright: Ambidextrous. Can use both hands (or feet) with equal, perfect skill. - Reversed: Perpetual Motion. Does not suffer from physical exhaustion while moving. Three of Pentacles - Upright: Material Intuition. Can \"hear\" if a machine or structure is about to break. - Reversed: Master's Hands. Their hands are naturally steady, even during an earthquake. Four of Pentacles - Upright: Hoarder's Memory. Knows the exact location of every item they own. - Reversed: Internal Clock. Always knows the exact time and date without a watch. Five of Pentacles - Upright: Immune System. Naturally resistant to all common diseases and infections. - Reversed: Cold-Blooded. Can survive in freezing temperatures without shivering or damage. Six of Pentacles - Upright: Appraising Eye. Can see the \"co","description":"","headingLevel":2,"fileSlug":"abilities"},{"title":"**Suit of Pentacles: Abilities of the Living Earth**","pageTitle":"abilities","breadcrumb":"abilities › **Suit of Pentacles: Abilities of the Living Earth**","url":"/generators/tarot/abilities/#suit-of-pentacles-abilities-of-the-living-earth","content":"Page of Pentacles - Upright: Earth-Child. Always knows exactly where they are in relation to the center of the earth. - Reversed: Stone-Skin. Their skin is naturally as tough as leather, providing a permanent armor bonus. Knight of Pentacles - Upright: Unstoppable. Cannot be slowed by mud, snow, sand, or any form of \"difficult terrain.\" - Reversed: Tremor-Sense. Can feel the heartbeat of any living thing touching the same ground as them. Queen of Pentacles - Upright: Abundance. Food and water in their possession never spoil and provide double nourishment. - Reversed: Green-Thumb. Can cause a plant to sprout or bloom instantly with a touch. King of Pentacles - Upright: Midas-Sight. Can see the \"weak point\" or structural flaw in any man-made object. - Reversed: Gilded Heart. Their body is naturally resistant to aging, decay, and necrotic energy.","description":"","headingLevel":2,"fileSlug":"abilities"},{"title":"**Suit of Swords: Abilities of Sharpness and Air**","pageTitle":"abilities","breadcrumb":"abilities › **Suit of Swords: Abilities of Sharpness and Air**","url":"/generators/tarot/abilities/#suit-of-swords-abilities-of-sharpness-and-air","content":"Ace of Swords - Upright: Hyper-Focus. Can slow down their perception of time for a single moment. - Reversed: Clarity. Their mind is naturally \"sharp,\" making them immune to confusion effects. Two of Swords - Upright: Perfect Pitch. An innate, perfect sense of hearing and sound frequency. - Reversed: Echolocation. Can \"see\" shapes in the dark by clicking or making noise. Three of Swords - Upright: Heart-Hardened. Physically feels less pain from chest or torso wounds. - Reversed: Sorrow-Speaker. Can communicate with the dying or those in deep coma. Four of Swords - Upright: Astral Projection. Can briefly \"leave\" their body while in a deep trance. - Reversed: Rapid Recovery. Their body naturally repairs bone and muscle while they sleep. Five of Swords - Upright: Weakness-Sense. Sees a faint \"glow\" around an enemy's physical weak spots. - Reversed: Survival Instinct. Automatically reacts to avoid a trap they didn't even see. Six of Swords - Upright: Water-Walker. Naturally buoyant and a w","description":"","headingLevel":2,"fileSlug":"abilities"},{"title":"**Suit of Swords: Abilities of the Keen Edge**","pageTitle":"abilities","breadcrumb":"abilities › **Suit of Swords: Abilities of the Keen Edge**","url":"/generators/tarot/abilities/#suit-of-swords-abilities-of-the-keen-edge","content":"Page of Swords - Upright: Wind-Whisperer. Can hear a whispered conversation from a supernatural distance. - Reversed: Sharp Tongue. Their insults or \"truths\" cause actual, minor physical pain to the target. Knight of Swords - Upright: Velocity. Moves faster than the eye can follow for a single, decisive strike. - Reversed: Air-Sense. Can feel the \"disturbance\" in the air from a projectile or hidden enemy. Queen of Swords - Upright: Severance. Can \"cut\" a magical effect or mental bond just by touching it. - Reversed: Cold Clarity. Their mind processes information so fast that the world appears to move in slow motion. King of Swords - Upright: Truth-Bringer. No one can tell a direct lie while standing within 5 feet of them. - Reversed: Iron Logic. Can \"calculate\" the exact path of a falling object or incoming attack perfectly.","description":"","headingLevel":2,"fileSlug":"abilities"},{"title":"**Suit of Wands: Abilities of Internal Fire**","pageTitle":"abilities","breadcrumb":"abilities › **Suit of Wands: Abilities of Internal Fire**","url":"/generators/tarot/abilities/#suit-of-wands-abilities-of-internal-fire","content":"Ace of Wands - Upright: High Metabolism. Naturally heals minor wounds and recovers stamina twice as fast. - Reversed: Thermal Resistance. An innate skin \"thickness\" that resists burns or extreme heat. Two of Wands - Upright: Panoramic Vision. A naturally wide field of vision; almost impossible to flank. - Reversed: Horizon Sense. An internal compass that always knows where \"home\" is. Three of Wands - Upright: Portent Dreams. Dreams often provide a vague but accurate look at the next day. - Reversed: Wind-Reader. Can feel changes in air pressure to predict incoming storms. Four of Wands - Upright: Harmonic Presence. Their mere arrival in a room lowers the heart rate of everyone in it. - Reversed: Anchor. They are physically harder to move or knock down when their feet are set. Five of Wands - Upright: Reflexive Counter. A natural \"twitch\" that allows them to parry before they think. - Reversed: Adrenaline Control. Can manually trigger an adrenaline dump for a short burst of speed. Six o","description":"","headingLevel":2,"fileSlug":"abilities"},{"title":"**Suit of Wands: Abilities of the Primal Spark**","pageTitle":"abilities","breadcrumb":"abilities › **Suit of Wands: Abilities of the Primal Spark**","url":"/generators/tarot/abilities/#suit-of-wands-abilities-of-the-primal-spark","content":"Page of Wands - Upright: Kindling. Their presence naturally increases the success rate of others' creative or physical actions. - Reversed: Flicker. Can briefly become invisible or \"unnoticeable\" as long as they are moving. Knight of Wands - Upright: Overdrive. Can push their body past its physical limits without feeling exhaustion until the task is done. - Reversed: Combustion. Can emit a physical \"shockwave\" of heat or energy when they are struck. Queen of Wands - Upright: Enthralling. A natural hypnotic quality to their gaze that makes it hard for others to look away. - Reversed: Fire-Brand. Their touch can leave a literal, glowing mark on an object or person that they can track. King of Wands - Upright: Sovereign Will. Immune to all forms of magical or mundane fear and intimidation. - Reversed: Eruption. Their shout can physically knock back enemies or shatter fragile glass.","description":"","headingLevel":2,"fileSlug":"abilities"},{"title":"backgrounds","pageTitle":"backgrounds","breadcrumb":"backgrounds","url":"/generators/tarot/backgrounds/","content":"Split the tarot Deck into Major arcana, all numbered suits, and all court suits to make 3 decks. The Major Arcana will help you pick a childhood background, the suit numbered cards will determine the adolescent background and the suit court cards will determine the young adult background. Childhood Backgrounds 0 The Fool - Upright: The Nomad. Raised in a rootless, traveling, or highly unstable family. - Reversed: The Caged Bird. An extremely sheltered upbringing that left them naive to danger. I The Magician - Upright: The Prodigy. Recognized very early for an innate talent and heavily pushed to excel. - Reversed: The Con Artist's Kin. Raised in an environment of deception, trickery, or \"smoke and mirrors.\" II The High Priestess - Upright: The Secret Holder. Born into a family protecting a crucial, ancient, or valuable secret. - Reversed: The Disconnected. Raised in a purely surface-level family that ignored intuition or depth. III The Empress - Upright: The Matriarch’s Legacy. A child","description":"","headingLevel":1,"fileSlug":"backgrounds"},{"title":"Suit of Cups: Emotion, Intimacy, and Imagination","pageTitle":"backgrounds","breadcrumb":"backgrounds › Suit of Cups: Emotion, Intimacy, and Imagination","url":"/generators/tarot/backgrounds/#suit-of-cups-emotion-intimacy-and-imagination","content":"Ace of Cups - Upright: The Awakening. An intense period of spiritual or creative discovery. - Reversed: The Heart-Close. A period of extreme emotional repression following a trauma. Two of Cups - Upright: The Soulmate. A history of a deep, formative, and possibly lost partnership. - Reversed: The Rejection. A core memory of being publicly or cruelly rejected by a peer. Three of Cups - Upright: The Inner Circle. Part of a legendary trio or group of inseparable friends. - Reversed: The Third Wheel. Spent their youth feeling like an afterthought in their own social group. Four of Cups - Upright: The Apathetic. Spent their youth \"bored\" or disconnected from all local opportunities. - Reversed: The Seeker. A period of trying every \"new thing\" to find a sense of meaning. Five of Cups - Upright: The Mourner. Defined by the loss of a friend or a major emotional disappointment. - Reversed: The Wallow. Refused to move on from a minor teenage heartbreak for years. Six of Cups - Upright: The Nosta","description":"","headingLevel":2,"fileSlug":"backgrounds"},{"title":"Suit of Cups: Reputation of Emotion & Connection","pageTitle":"backgrounds","breadcrumb":"backgrounds › Suit of Cups: Reputation of Emotion & Connection","url":"/generators/tarot/backgrounds/#suit-of-cups-reputation-of-emotion-connection","content":"Page of Cups - Upright: The Artist. Known for a unique, sensitive perspective and a gentle public demeanor. - Reversed: The Escapist. A history of disappearing into substance use or fantasy when things get real. Knight of Cups - Upright: The Romantic. Famous for grand gestures and a \"knight in shining armor\" reputation. - Reversed: The Heartbreaker. Known for seducing people with false promises of emotional depth. Queen of Cups - Upright: The Healer. A reputation as the community \"anchor\" who everyone goes to for advice. - Reversed: The Emotional Leech. Known for \"vampiric\" relationships where they drain others' energy. King of Cups - Upright: The Stoic. Known for extreme emotional intelligence and remaining calm in any crisis. - Reversed: The Puppet Master. A reputation for using their understanding of people to pull strings.","description":"","headingLevel":2,"fileSlug":"backgrounds"},{"title":"Suit of Pentacles: Reputation of Status & Security","pageTitle":"backgrounds","breadcrumb":"backgrounds › Suit of Pentacles: Reputation of Status & Security","url":"/generators/tarot/backgrounds/#suit-of-pentacles-reputation-of-status-security","content":"Page of Pentacles - Upright: The Scholar. Known as a lifelong student who is always mastering a new, practical skill. - Reversed: The Perpetual Amateur. A reputation for buying the \"lifestyle\" of success without the work. Knight of Pentacles - Upright: The Rock. Famous for being the most reliable person alive; if they say it, it happens. - Reversed: The Drifter. Known for lacking any direction or ambition, despite having potential. Queen of Pentacles - Upright: The Provider. A reputation for building a comfortable, wealthy life and sharing it. - Reversed: The Social Climber. Known for valuing status symbols and \"the right people\" over everything. King of Pentacles - Upright: The Magnate. Gained a reputation for immense financial success and business acumen. - Reversed: The Mercenary. Known for doing anything—legal or otherwise—solely for a paycheck.","description":"","headingLevel":2,"fileSlug":"backgrounds"},{"title":"Suit of Pentacles: Work, Money, and Physicality","pageTitle":"backgrounds","breadcrumb":"backgrounds › Suit of Pentacles: Work, Money, and Physicality","url":"/generators/tarot/backgrounds/#suit-of-pentacles-work-money-and-physicality","content":"Ace of Pentacles - Upright: The Heir. Received a significant gift, inheritance, or job offer early on. - Reversed: The Squanderer. Lost a major financial or physical opportunity through neglect. Two of Pentacles - Upright: The Hustler. Spent their youth working multiple jobs or \"juggling\" survival. - Reversed: The Unbalanced. A history of being unable to manage their own life or health. Three of Pentacles - Upright: The Artisan. Spent years as an apprentice, gaining a reputation for skill. - Reversed: The Unskilled. Pretended to have a trade they didn't actually master. Four of Pentacles - Upright: The Hoarder. A youth spent obsessively saving resources out of fear of lack. - Reversed: The Spendthrift. Gained a reputation for losing money as fast as they made it. Five of Pentacles - Upright: The Destitute. Spent years in extreme poverty or \"roughing it\" on the streets. - Reversed: The Bad Debt. Owes significant favors from this period that still plague them. Six of Pentacles - Upright:","description":"","headingLevel":2,"fileSlug":"backgrounds"},{"title":"Suit of Swords: Intellect, Conflict, and Truth","pageTitle":"backgrounds","breadcrumb":"backgrounds › Suit of Swords: Intellect, Conflict, and Truth","url":"/generators/tarot/backgrounds/#suit-of-swords-intellect-conflict-and-truth","content":"Ace of Swords - Upright: The Intellectual. Achieved a breakthrough or clarity that changed their worldview. - Reversed: The Muddled. Spent their youth in a state of deep mental confusion or propaganda. Two of Swords - Upright: The Fence-Sitter. Refused to take a side in a major peer or family conflict. - Reversed: The Forced Choice. Made a split-second decision that had permanent consequences. Three of Swords - Upright: The Great Betrayal. Experienced a heartbreak that redefined how they view trust. - Reversed: The Scarred. Carried a literal or figurative wound from a childhood conflict. Four of Swords - Upright: The Convalescent. Spent a large portion of youth recovering from illness or injury. - Reversed: The Burnout. Pushed their mind too hard (study/work) and lost their spark. Five of Swords - Upright: The Hollow Victor. Won a major social conflict but lost all their friends in the process. - Reversed: The Humiliated. A history of being \"put in their place\" publicly. Six of Swords ","description":"","headingLevel":2,"fileSlug":"backgrounds"},{"title":"Suit of Swords: Reputation of Intellect & Authority","pageTitle":"backgrounds","breadcrumb":"backgrounds › Suit of Swords: Reputation of Intellect & Authority","url":"/generators/tarot/backgrounds/#suit-of-swords-reputation-of-intellect-authority","content":"Page of Swords - Upright: The Watcher. Known for being the most observant person in the room; a natural spy. - Reversed: The Gossip. Gained a reputation for weaponizing secrets and spreading misinformation. Knight of Swords - Upright: The Crusader. Famous for an uncompromising pursuit of justice or a specific truth. - Reversed: The Fanatic. Known for being \"right\" at the cost of being human; socially abrasive. Queen of Swords - Upright: The Analyst. A reputation for being sharp, blunt, and impossible to lie to. - Reversed: The Ice Queen/King. Known for being needlessly cruel or emotionally disconnected. King of Swords - Upright: The Judge. Gained a reputation as a fair, logical, and highly respected authority figure. - Reversed: The Corruptor. Known for using the law or logic to benefit themselves and hurt rivals.","description":"","headingLevel":2,"fileSlug":"backgrounds"},{"title":"Suit of Wands: Ambition, Drive, and Conflict","pageTitle":"backgrounds","breadcrumb":"backgrounds › Suit of Wands: Ambition, Drive, and Conflict","url":"/generators/tarot/backgrounds/#suit-of-wands-ambition-drive-and-conflict","content":"Ace of Wands - Upright: The First Call. Discovered their true passion and left home early to pursue it. - Reversed: The False Start. Tried and failed to pursue a dream, resulting in a humiliating return. Two of Wands - Upright: The Voyager. Spent their youth planning a grand escape or a major life change. - Reversed: The Grounded. Had grand plans that were systematically crushed by local reality. Three of Wands - Upright: The Pioneer. Led a group of peers into a new, successful venture or territory. - Reversed: The Stranded. Left their home for a promise that turned out to be a lie. Four of Wands - Upright: The Socialite. Defined by a vibrant, celebratory, and highly popular social life. - Reversed: The Crasher. Always on the outside of social circles, never truly \"invited\" in. Five of Wands - Upright: The Rivalry. Defined by an intense, prolonged competition with a specific peer. - Reversed: The Pacifist. A history of breaking up fights and mediating peer conflicts. Six of Wands - Upr","description":"","headingLevel":2,"fileSlug":"backgrounds"},{"title":"Suit of Wands: Reputation of Passion & Action","pageTitle":"backgrounds","breadcrumb":"backgrounds › Suit of Wands: Reputation of Passion & Action","url":"/generators/tarot/backgrounds/#suit-of-wands-reputation-of-passion-action","content":"Page of Wands - Upright: The Catalyst. Known for sparking new movements or being the \"idea person\" in a group. - Reversed: The Flake. Gained a reputation for starting massive projects and abandoning them midway. Knight of Wands - Upright: The Adventurer. Famous for high-risk, high-reward exploits and a fearless attitude. - Reversed: The Loose Cannon. Known for a volatile temper and causing property or social damage. Queen of Wands - Upright: The Influencer. A social powerhouse whose approval can make or break someone’s career. - Reversed: The Social Extinguisher. Known for jealousy and blacklisting anyone who outshines them. King of Wands - Upright: The Visionary. An established leader who built something from nothing through sheer will. - Reversed: The Despot. A reputation for running their business or home like a high-pressure dictatorship.","description":"","headingLevel":2,"fileSlug":"backgrounds"},{"title":"character-sentence","pageTitle":"character-sentence","breadcrumb":"character-sentence","url":"/generators/tarot/character-sentence/","content":"Split the tarot Deck into Major arcana, all numbered suits, and all court suits to make 3 decks. The Major Arcana will help you pick a descriptor, the suit court cards will determine the type and the numbered suit cards will determine the does something special. Descriptor","description":"","headingLevel":1,"fileSlug":"character-sentence"},{"title":"Major Arcana: The Descriptors (Adjectives)","pageTitle":"character-sentence","breadcrumb":"character-sentence › Major Arcana: The Descriptors (Adjectives)","url":"/generators/tarot/character-sentence/#major-arcana-the-descriptors-adjectives","content":"0 The Fool - Upright: Carefree. A character unburdened by worry or consequence. - Reversed: Reckless. A character who ignores all red flags. I The Magician - Upright: Resourceful. A character who can make a tool out of anything. - Reversed: Manipulative. A character who views people as instruments. II The High Priestess - Upright: Enigmatic. A character who is a deep, quiet mystery. - Reversed: Secretive. A character who hides things even when it's unnecessary. III The Empress - Upright: Nurturing. A character who naturally grows and protects life. - Reversed: Smothering. A character whose \"care\" is a form of control. IV The Emperor - Upright: Disciplined. A character defined by structure and order. - Reversed: Tyrannical. A character who demands absolute obedience. V The Hierophant - Upright: Traditional. A character who is a pillar of their community. - Reversed: Subversive. A character who actively challenges the status quo. VI The Lovers - Upright: Devoted. A character defined by t","description":"","headingLevel":2,"fileSlug":"character-sentence"},{"title":"Suit of Cups: Actions of Soul","pageTitle":"character-sentence","breadcrumb":"character-sentence › Suit of Cups: Actions of Soul","url":"/generators/tarot/character-sentence/#suit-of-cups-actions-of-soul","content":"Ace - Upright: ...who channels emotional power. - Reversed: ...who repels all emotional connection. Two - Upright: ...who forges unbreakable bonds. - Reversed: ...who breaks every promise they make. Three - Upright: ...who unites disparate groups. - Reversed: ...who isolates themselves from the group. Four - Upright: ...who finds clarity in silence. - Reversed: ...who discards perfectly good chances. Five - Upright: ...who reclaims beauty from loss. - Reversed: ...who wallows in ancient heartbreaks. Six - Upright: ...who restores forgotten memories. - Reversed: ...who clings to a dead past. Seven - Upright: ...who conjures vivid illusions. - Reversed: ...who confuses dreams for reality. Eight - Upright: ...who walks away from everything. - Reversed: ...who returns to a toxic life. Nine - Upright: ...who grants the wishes of others. - Reversed: ...who denies themselves any joy. Ten - Upright: ...who creates lasting harmony. - Reversed: ...who shatters a family’s peace.","description":"","headingLevel":2,"fileSlug":"character-sentence"},{"title":"Suit of Cups: The Relational Types","pageTitle":"character-sentence","breadcrumb":"character-sentence › Suit of Cups: The Relational Types","url":"/generators/tarot/character-sentence/#suit-of-cups-the-relational-types","content":"Page of Cups - Upright: The Idealist. One who sees the beauty and potential in everything. - Reversed: The Escapist. One who hides from reality in dreams or substances. Knight of Cups - Upright: The Envoy. One who carries messages of peace, love, or alliance. - Reversed: The Heartbreaker. One who manipulates the emotions of others for sport. Queen of Cups - Upright: The Confidant. One who provides a safe harbor and deep counsel. - Reversed: The Martyr. One who drains others by constantly playing the victim. King of Cups - Upright: The Mediator. One who balances warring factions and keeps the peace. - Reversed: The Puppeteer. One who uses emotional intelligence to pull strings.","description":"","headingLevel":2,"fileSlug":"character-sentence"},{"title":"Suit of Pentacles: Actions of Body","pageTitle":"character-sentence","breadcrumb":"character-sentence › Suit of Pentacles: Actions of Body","url":"/generators/tarot/character-sentence/#suit-of-pentacles-actions-of-body","content":"Ace - Upright: ...who discovers hidden wealth. - Reversed: ...who squanders a golden opportunity. Two - Upright: ...who juggles impossible demands. - Reversed: ...who fumbles a delicate balance. Three - Upright: ...who builds lasting monuments. - Reversed: ...who sabotages the work of masters. Four - Upright: ...who secures vital resources. - Reversed: ...who hoards what they cannot use. Five - Upright: ...who endures extreme hardship. - Reversed: ...who begs for what they should earn. Six - Upright: ...who distributes wealth and favors. - Reversed: ...who uses charity to control others. Seven - Upright: ...who waits for the long harvest. - Reversed: ...who abandons the harvest too early. Eight - Upright: ...who masters complex crafts. - Reversed: ...who shortcuts a complex process. Nine - Upright: ...who tames the wild world. - Reversed: ...who pretends to be self-made. Ten - Upright: ...who upholds a massive legacy. - Reversed: ...who dishonors a family name.","description":"","headingLevel":2,"fileSlug":"character-sentence"},{"title":"Suit of Pentacles: The Material Types","pageTitle":"character-sentence","breadcrumb":"character-sentence › Suit of Pentacles: The Material Types","url":"/generators/tarot/character-sentence/#suit-of-pentacles-the-material-types","content":"Page of Pentacles - Upright: The Scholar. One who is dedicated to learning a specific, practical trade. - Reversed: The Scavenger. One who survives on the scraps and leavings of others. Knight of Pentacles - Upright: The Warden. One who protects resources and ensures everything runs on time. - Reversed: The Drifter. One who lacks a home, a trade, or a steady purpose. Queen of Pentacles - Upright: The Provider. One who builds a community and ensures its material comfort. - Reversed: The Socialite. One who values status symbols and wealth above all else. King of Pentacles - Upright: The Magnate. One who has built a physical empire or massive estate. - Reversed: The Hoarder. One who accumulates wealth but refuses to use or share it. Does Something Special","description":"","headingLevel":2,"fileSlug":"character-sentence"},{"title":"Suit of Swords: Actions of Mind","pageTitle":"character-sentence","breadcrumb":"character-sentence › Suit of Swords: Actions of Mind","url":"/generators/tarot/character-sentence/#suit-of-swords-actions-of-mind","content":"Ace - Upright: ...who strikes with mental clarity. - Reversed: ...who muddles the truth with lies. Two - Upright: ...who balances on the edge of indecision. - Reversed: ...who refuses to see the obvious. Three - Upright: ...who heals through painful truths. - Reversed: ...who weaponizes their old wounds. Four - Upright: ...who recovers in the midst of battle. - Reversed: ...who burns out at the worst moment. Five - Upright: ...who wins at any cost. - Reversed: ...who loses with zero dignity. Six - Upright: ...who guides others through stormy waters. - Reversed: ...who drifts into dangerous territory. Seven - Upright: ...who steals from the shadows. - Reversed: ...who gets caught in their own web. Eight - Upright: ...who escapes every cage. - Reversed: ...who traps themselves in a mental cage. Nine - Upright: ...who weaponizes the fears of others. - Reversed: ...who succumbs to their own nightmares. Ten - Upright: ...who survives total betrayal. - Reversed: ...who invites their own betr","description":"","headingLevel":2,"fileSlug":"character-sentence"},{"title":"Suit of Swords: The Intellectual Types","pageTitle":"character-sentence","breadcrumb":"character-sentence › Suit of Swords: The Intellectual Types","url":"/generators/tarot/character-sentence/#suit-of-swords-the-intellectual-types","content":"Page of Swords - Upright: The Informant. One who watches, listens, and gathers vital data. - Reversed: The Slanderer. One who weaponizes secrets to destroy enemies. Knight of Swords - Upright: The Zealot. One who pursues a truth or cause with absolute focus. - Reversed: The Iconoclast. One who seeks to destroy all established beliefs. Queen of Swords - Upright: The Arbitrator. One who cuts through lies to find the objective truth. - Reversed: The Cynic. One who believes everything is inherently broken or corrupt. King of Swords - Upright: The Strategist. One who masters the rules of the game to win. - Reversed: The Executioner. One who delivers cold, final judgment without mercy.","description":"","headingLevel":2,"fileSlug":"character-sentence"},{"title":"Suit of Wands: Actions of Will","pageTitle":"character-sentence","breadcrumb":"character-sentence › Suit of Wands: Actions of Will","url":"/generators/tarot/character-sentence/#suit-of-wands-actions-of-will","content":"Ace - Upright: ...who ignites new movements. - Reversed: ...who extinguishes the sparks of others. Two - Upright: ...who charts unknown horizons. - Reversed: ...who hesitates at the finish line. Three - Upright: ...who commands distant ventures. - Reversed: ...who ignores the warnings of the sea. Four - Upright: ...who fosters safe havens. - Reversed: ...who disrupts the peace of home. Five - Upright: ...who thrives in chaotic competition. - Reversed: ...who incites needless brawls. Six - Upright: ...who inspires public victory. - Reversed: ...who fakes a legendary reputation. Seven - Upright: ...who defends the impossible high-ground. - Reversed: ...who surrenders to the smallest pressure. Eight - Upright: ...who delivers messages at blurring speeds. - Reversed: ...who stagnates in a fast world. Nine - Upright: ...who guards the final threshold. - Reversed: ...who leaves the gate wide open. Ten - Upright: ...who shoulders the burdens of others. - Reversed: ...who collapses under a sel","description":"","headingLevel":2,"fileSlug":"character-sentence"},{"title":"Suit of Wands: The Catalyst Types","pageTitle":"character-sentence","breadcrumb":"character-sentence › Suit of Wands: The Catalyst Types","url":"/generators/tarot/character-sentence/#suit-of-wands-the-catalyst-types","content":"Page of Wands - Upright: The Trailblazer. One who finds new paths or starts new trends. - Reversed: The Firebrand. One who agitates and stirs up trouble for its own sake. Knight of Wands - Upright: The Daredevil. One who takes high-speed risks to achieve glory. - Reversed: The Mercenary. One who fights only for the thrill or the payout. Queen of Wands - Upright: The Icon. One who leads through charisma and sheer force of personality. - Reversed: The Rival. One who seeks to outshine or sabotage all competition. King of Wands - Upright: The Commander. One who directs others toward a grand, singular vision. - Reversed: The Autocrat. One who demands total control over every subordinate.","description":"","headingLevel":2,"fileSlug":"character-sentence"},{"title":"flaws","pageTitle":"flaws","breadcrumb":"flaws","url":"/generators/tarot/flaws/","content":"Flaws","description":"","headingLevel":1,"fileSlug":"flaws"},{"title":"Suit of Cups: Flaws of Emotion and Intimacy","pageTitle":"flaws","breadcrumb":"flaws › Suit of Cups: Flaws of Emotion and Intimacy","url":"/generators/tarot/flaws/#suit-of-cups-flaws-of-emotion-and-intimacy","content":"Ace of Cups - Upright: Emotional Volatility. Being ruled by the \"mood of the hour.\" - Reversed: Emotional Blockage. Repressing feelings until they leak out sideways. Two of Cups - Upright: Codependency. Losing one's identity within a partnership. - Reversed: Social Friction. A \"lone wolf\" attitude masking fear of rejection. Three of Cups - Upright: Over-indulgence. Using social life as a mask for internal pain. - Reversed: Hedonism. Partying to the point of literal self-destruction. Four of Cups - Upright: Apathy. Being bored by everything; emotional shut-down. - Reversed: Restlessness. A \"grass is greener\" mentality that prevents peace. Five of Cups - Upright: Melancholy. Refusing to look at what is left due to grief. - Reversed: Self-Pity. Wallowing in old wounds to avoid fixing them. Six of Cups - Upright: Nostalgia. Living in the past and resenting the present. - Reversed: Arrested Development. Being \"stuck\" at a specific age mentally. Seven of Cups - Upright: Escapism. Living in a","description":"","headingLevel":2,"fileSlug":"flaws"},{"title":"Suit of Cups: The Identity of Emotion","pageTitle":"flaws","breadcrumb":"flaws › Suit of Cups: The Identity of Emotion","url":"/generators/tarot/flaws/#suit-of-cups-the-identity-of-emotion","content":"Page of Cups - Upright: Sensitivity. Taking every comment as a deep, personal wound. - Reversed: Escapism. Retiring into a dream world to avoid real-world consequences. Knight of Cups - Upright: Unrealistic. Falling in love with the \"idea\" of people rather than the person. - Reversed: Melodrama. Creating emotional crises just to feel something. Queen of Cups - Upright: Smothering. Caring for others so intensely that it becomes a form of control. - Reversed: Instability. Projecting their own internal chaos onto their loved ones. King of Cups - Upright: Stoicism. Being so \"controlled\" that they appear cold and unfeeling. - Reversed: Coldness. Using their understanding of emotions to manipulate others' feelings.","description":"","headingLevel":2,"fileSlug":"flaws"},{"title":"Suit of Pentacles: Flaws of Materiality and Security","pageTitle":"flaws","breadcrumb":"flaws › Suit of Pentacles: Flaws of Materiality and Security","url":"/generators/tarot/flaws/#suit-of-pentacles-flaws-of-materiality-and-security","content":"Ace of Pentacles - Upright: Materialism. Valuing objects and status over people. - Reversed: Greed. Hoarding opportunities and resources \"just in case. Two of Pentacles - Upright: Unreliability. Juggling too many tasks and dropping the balls. - Reversed: Disorganization. A chaotic lifestyle where they lose everything. Three of Pentacles - Upright: Elitism. Judging others based on professional skill level. - Reversed: Fraudulence. Pretending to be an expert while being a novice. Four of Pentacles - Upright: Stinginess. Hoarding money, resources, or affection. - Reversed: Possessiveness. Treating people like objects they \"own.\" Five of Pentacles - Upright: Poverty Mindset. Feeling \"lack\" even when they have enough. - Reversed: Spiritual Poverty. Having money but feeling worthless. Six of Pentacles - Upright: Power-Tripping. Giving charity only to feel superior. - Reversed: Debt. Borrowing more (money or favors) than they can repay. Seven of Pentacles - Upright: Discontent. Working hard b","description":"","headingLevel":2,"fileSlug":"flaws"},{"title":"Suit of Pentacles: The Identity of Security","pageTitle":"flaws","breadcrumb":"flaws › Suit of Pentacles: The Identity of Security","url":"/generators/tarot/flaws/#suit-of-pentacles-the-identity-of-security","content":"Page of Pentacles - Upright: Dilettante. Buying all the gear for a hobby/job but never doing the work. - Reversed: Laziness. Expecting the world to provide a lifestyle they haven't earned. Knight of Pentacles - Upright: Stagnation. Refusing to change a routine even when it clearly isn't working. - Reversed: Boredom. Losing all passion for life because they are too focused on \"safety.\" Queen of Pentacles - Upright: Possessiveness. Treating their home and family like assets to be managed. - Reversed: Insecurity. Constantly comparing their material worth to everyone else's. King of Pentacles - Upright: Greed. Measuring their personal value solely by their bank account. - Reversed: Materialism. Obsessing over status symbols to hide a lack of character.","description":"","headingLevel":2,"fileSlug":"flaws"},{"title":"Suit of Swords: Flaws of Logic and Conflict","pageTitle":"flaws","breadcrumb":"flaws › Suit of Swords: Flaws of Logic and Conflict","url":"/generators/tarot/flaws/#suit-of-swords-flaws-of-logic-and-conflict","content":"Ace of Swords - Upright: Brutality. Using \"the truth\" as a weapon to hurt others. - Reversed: Confusion. Total inability to think clearly or decide. Two of Swords - Upright: Avoidance. Refusing to see a painful truth in front of them. - Reversed: Information Overload. Paralyzed by too many facts and no gut feeling. Three of Swords - Upright: Self-Sabotage. Harboring a \"broken heart\" as a personality trait. - Reversed: Repression. Refusing to acknowledge they are even hurt. Four of Swords - Upright: Withdrawal. Using \"rest\" to hide from social obligations. - Reversed: Burnout. Ignoring the need for rest until the body collapses. Five of Swords - Upright: Ruthlessness. Needing to win at any cost, even if left alone. - Reversed: Humiliation. Harboring revenge fantasies after a public defeat. Six of Swords - Upright: Baggage. Carrying mental trauma into every new situation. - Reversed: Stagnation. Refusing to move on from a toxic environment. Seven of Swords - Upright: Deceit. A habit of o","description":"","headingLevel":2,"fileSlug":"flaws"},{"title":"Suit of Swords: The Identity of Intellect","pageTitle":"flaws","breadcrumb":"flaws › Suit of Swords: The Identity of Intellect","url":"/generators/tarot/flaws/#suit-of-swords-the-identity-of-intellect","content":"Page of Swords - Upright: Snoopiness. Obsessively gathering \"dirt\" on others to feel powerful. - Reversed: Deceit. Spreading rumors or false logic to see who is foolish enough to believe. Knight of Swords - Upright: Fanaticism. Charging toward a \"truth\" without considering the human cost. - Reversed: Insolence. Disrespecting anyone they deem \"less intelligent\" than themselves. Queen of Swords - Upright: Cynicism. Expecting the worst from people and punishing them for it. - Reversed: Bitterness. Holding onto old arguments like a holy relic. King of Swords - Upright: Judgment. Assessing everyone by a rigid, logical, and unfeeling metric. - Reversed: Cruelty. Using logic to systematically dismantle someone else's confidence.","description":"","headingLevel":2,"fileSlug":"flaws"},{"title":"Suit of Wands: Flaws of Drive and Ego","pageTitle":"flaws","breadcrumb":"flaws › Suit of Wands: Flaws of Drive and Ego","url":"/generators/tarot/flaws/#suit-of-wands-flaws-of-drive-and-ego","content":"Ace of Wands - Upright: Hyperactivity. Starting projects but never finishing them. - Reversed: Lack of Initiative. Waiting for a sign that never comes. Two of Wands - Upright: Arrogance. Thinking one is \"too big\" for their surroundings. - Reversed: Fear of the Unknown. Choosing a safe, miserable life over risk. Three of Wands - Upright: Detachment. Always looking ahead and never being present. - Reversed: Short-sightedness. Failing to plan beyond the next five minutes. Four of Wands - Upright: Complacency. Getting too comfortable and refusing to grow. - Reversed: Unsettledness. A refusal to ever \"put down roots\" or commit. Five of Wands - Upright: Contradictoriness. Arguing just for the sake of friction. - Reversed: Conflict Avoidance. Letting others walk all over them for \"peace.\" Six of Wands - Upright: Narcissism. A desperate need for public applause. - Reversed: Disrepute. A \"fall from grace\" that leads to bitter resentment. Seven of Wands - Upright: Defensiveness. Treating every s","description":"","headingLevel":2,"fileSlug":"flaws"},{"title":"Suit of Wands: The Identity of Ego","pageTitle":"flaws","breadcrumb":"flaws › Suit of Wands: The Identity of Ego","url":"/generators/tarot/flaws/#suit-of-wands-the-identity-of-ego","content":"Page of Wands - Upright: Faddism. Constantly chasing the \"next big thing\" and never committing. - Reversed: Indecisiveness. A total lack of personal fire; waiting for others to lead. Knight of Wands - Upright: Impulsivity. \"Leaping before looking\" in a way that endangers others. - Reversed: Short-Temperedness. A \"hair-trigger\" personality that explodes at minor inconveniences. Queen of Wands - Upright: Domineering. Demanding to be the center of attention in every room. - Reversed: Jealousy. Actively undermining anyone they perceive as a threat to their \"throne.\" King of Wands - Upright: Intolerance. Refusing to listen to any opinion that isn't their own. - Reversed: Abrasiveness. Being so \"brutally honest\" that they become a social pariah.","description":"","headingLevel":2,"fileSlug":"flaws"},{"title":"The Major Arcana","pageTitle":"flaws","breadcrumb":"flaws › The Major Arcana","url":"/generators/tarot/flaws/#the-major-arcana","content":"0 The Fool - Upright: Recklessness. Acting without considering consequences. - Reversed: Stagnation. Paralyzing fear of taking any risks at all. I The Magician - Upright: Manipulation. Using talents to control or deceive others. - Reversed: Creative Blockage. Feeling powerless or lacking the will to act. II The High Priestess - Upright: Secretiveness. Withholding vital information to maintain an edge. - Reversed: Superficiality. Ignoring intuition in favor of purely surface-level logic. III The Empress - Upright: Smothering. Overbearing \"protection\" that stunts others' growth. - Reversed: Negligence. Lack of self-care or failure to nurture projects and people. IV The Emperor - Upright: Tyranny. Inflexible need for total control and order. - Reversed: Incompetence. Inability to lead or maintain personal boundaries. V The Hierophant - Upright: Dogmatism. Blindly following tradition even when it is harmful. - Reversed: Rebellion. Aimless defiance of any structure just for the sake of it. ","description":"","headingLevel":2,"fileSlug":"flaws"},{"title":"skills","pageTitle":"skills","breadcrumb":"skills","url":"/generators/tarot/skills/","content":"","description":"","headingLevel":1,"fileSlug":"skills"},{"title":"Major Arcana: Master Skills","pageTitle":"skills","breadcrumb":"skills › Major Arcana: Master Skills","url":"/generators/tarot/skills/#major-arcana-master-skills","content":"0 The Fool - Upright: Parkour/Free-Running. The skill of moving through dangerous terrain with zero hesitation. - Reversed: Danger Sensing. A \"sixth sense\" for walking into traps or bad situations. I The Magician - Upright: Sleight of Hand. Expert manual dexterity, card tricks, and pocket-picking. - Reversed: False Alchemy. The skill of creating convincing fakes, forgeries, or \"miracles.\" II The High Priestess - Upright: Cipher-Breaking. The skill of reading codes, hidden languages, and subtext. - Reversed: Occult Lore. Knowledge of \"forbidden\" or forgotten rituals and myths. III The Empress - Upright: Botany/Herbalism. Mastery of growing plants and creating natural medicines. - Reversed: Luxury Curation. The skill of managing high-end aesthetics, fashion, or interiors. IV The Emperor - Upright: Strategic Command. The skill of directing troops or large groups in high-stakes conflict. - Reversed: Bureaucracy. Navigating complex government systems and legal red tape. V The Hierophant - U","description":"","headingLevel":2,"fileSlug":"skills"},{"title":"Suit of Cups: Skills of Intuition and Connection","pageTitle":"skills","breadcrumb":"skills › Suit of Cups: Skills of Intuition and Connection","url":"/generators/tarot/skills/#suit-of-cups-skills-of-intuition-and-connection","content":"Page of Cups - Upright: Artistic Expression. Mastery over painting, poetry, or music that touches the soul. - Reversed: Dream-Walking. The skill of using meditation or substances to gain \"visions.\" Knight of Cups - Upright: Etiquette/Chivalry. Mastery of the \"old ways\" of formal social conduct and honor. - Reversed: Flattery. The skill of telling people exactly what they want to hear to get what you want. Queen of Cups - Upright: Emotional Mirroring. The skill of making anyone feel like you are their oldest, truest friend. - Reversed: Guilt-Tripping. The skill of using emotional history to bind someone to your will. King of Cups - Upright: Diplomacy/Statecraft. The skill of maintaining peace between warring, emotional factions. - Reversed: Emotional Cold-Reading. Knowing a person's deepest trauma just by looking at them.","description":"","headingLevel":2,"fileSlug":"skills"},{"title":"Suit of Cups: Skills of Intuition and Social Arts","pageTitle":"skills","breadcrumb":"skills › Suit of Cups: Skills of Intuition and Social Arts","url":"/generators/tarot/skills/#suit-of-cups-skills-of-intuition-and-social-arts","content":"Ace of Cups - Upright: Empathic Tuning. Instantly sensing the hidden \"vibe\" of a person or room. - Reversed: Emotional Masking. Hiding all personal feelings from observation. Two of Cups - Upright: Negotiation. The skill of finding a \"win-win\" in a personal or legal dispute. - Reversed: Seduction. The skill of using personal charm to gain information or favor. Three of Cups - Upright: Hospitality. Making anyone feel at home to lower their guard. - Reversed: Social Intelligence. Identifying the \"alpha\" and the \"outcast\" in any group. Four of Cups - Upright: Meditation. Using quiet time to solve complex mental puzzles. - Reversed: Scavenging. Finding value in things that others have overlooked or discarded. Five of Cups - Upright: Grief Counseling. Helping others process trauma to keep a team functional. - Reversed: Poisoning (Emotional). Knowing exactly how to ruin someone's morale. Six of Cups - Upright: Childhood Lore. Knowledge of nursery rhymes, myths, and connecting with kids. - Re","description":"","headingLevel":2,"fileSlug":"skills"},{"title":"Suit of Pentacles: Skills of Craft and Materiality","pageTitle":"skills","breadcrumb":"skills › Suit of Pentacles: Skills of Craft and Materiality","url":"/generators/tarot/skills/#suit-of-pentacles-skills-of-craft-and-materiality","content":"Ace of Pentacles - Upright: Appraisal. Knowing the exact market value of any physical object. - Reversed: Investment. Identifying which assets will gain value over time. Two of Pentacles - Upright: Acrobatics. Physical skill in balance, juggling, and agility. - Reversed: Resource Management. Making a small amount of food or money last weeks. Three of Pentacles - Upright: Architecture/Masonry. Designing and building lasting physical structures. - Reversed: Professional Networking. Recruiting the right experts for a job. Four of Pentacles - Upright: Accountancy. Tracking resources with zero room for error. - Reversed: Security Auditing. Identifying the physical \"holes\" in a vault or fortress. Five of Pentacles - Upright: Urban Survival. Finding shelter and warmth in a hostile, poor environment. - Reversed: Begging/Conning. The skill of looking \"pitiful\" to gain resources. Six of Pentacles - Upright: Patronage. Convincing wealthy people to fund your specific projects. - Reversed: Debt Tra","description":"","headingLevel":2,"fileSlug":"skills"},{"title":"Suit of Pentacles: Skills of Trade and Materiality","pageTitle":"skills","breadcrumb":"skills › Suit of Pentacles: Skills of Trade and Materiality","url":"/generators/tarot/skills/#suit-of-pentacles-skills-of-trade-and-materiality","content":"Page of Pentacles - Upright: Technical Research. The skill of learning the \"how-to\" of any machine or process quickly. - Reversed: Scavenging/Salvage. Finding valuable components in literal piles of trash. Knight of Pentacles - Upright: Logistics/Supply. The skill of moving massive amounts of goods safely over long distances. - Reversed: Fortification-Testing. Identifying the one \"physical\" weak spot in a door, wall, or lock. Queen of Pentacles - Upright: Resource Husbandry. The skill of making an estate, home, or business thrive and grow. - Reversed: Luxury Smuggling. The skill of moving high-end, illegal goods through \"proper\" channels. King of Pentacles - Upright: Financial Empire-Building. The skill of turning a single coin into a mountain of gold. - Reversed: Bribery/Corruption. The skill of knowing exactly who to pay and how much to get a result.","description":"","headingLevel":2,"fileSlug":"skills"},{"title":"Suit of Swords: Skills of Intellect and Conflict","pageTitle":"skills","breadcrumb":"skills › Suit of Swords: Skills of Intellect and Conflict","url":"/generators/tarot/skills/#suit-of-swords-skills-of-intellect-and-conflict","content":"Ace of Swords - Upright: Critical Analysis. Finding the one \"weak point\" in armor or an argument. - Reversed: Propaganda. Crafting a \"truth\" that benefits your side. Two of Swords - Upright: Blind-Fighting. Operating effectively when vision is blocked or obscured. - Reversed: Decision-Mapping. Outlining all possible outcomes of a complex choice. Three of Swords - Upright: Surgery/Anatomy. Precision cutting for medical or scientific purposes. - Reversed: Heart-Breaking. The verbal skill of crushing someone's spirit. Four of Swords - Upright: Lucid Dreaming. Solving problems during deep, controlled rest. - Reversed: Recovery Tech. The skill of bringing a \"downed\" ally back to consciousness. Five of Swords - Upright: Dirty Fighting. Skill in pocket-sand, low blows, and dishonorable tactics. - Reversed: Humiliation. Publicly dismantling a rival's logic or social standing. Six of Swords - Upright: Safe Passage. Moving people through dangerous territory without a trace. - Reversed: Baggage S","description":"","headingLevel":2,"fileSlug":"skills"},{"title":"Suit of Swords: Skills of Logic and Wit","pageTitle":"skills","breadcrumb":"skills › Suit of Swords: Skills of Logic and Wit","url":"/generators/tarot/skills/#suit-of-swords-skills-of-logic-and-wit","content":"Page of Swords - Upright: Surveillance. The skill of watching a target for days without ever being spotted. - Reversed: Slander/Libel. The skill of writing or speaking in a way that ruins a reputation. Knight of Swords - Upright: Interrogation. The skill of using rapid-fire logic to \"break\" a suspect's story. - Reversed: Blitz-Tactics. The skill of winning a fight or argument through sheer, overwhelming speed. Queen of Swords - Upright: Objective Auditing. The skill of finding the \"rot\" or \"lie\" in any system or person. - Reversed: Sarcasm/Wit. Using language as a weapon to dismantle an opponent's confidence. King of Swords - Upright: Jurisprudence. Mastery of the high law, sentencing, and philosophical logic. - Reversed: Ruthless Prosecution. The skill of ensuring someone is convicted, regardless of innocence.","description":"","headingLevel":2,"fileSlug":"skills"},{"title":"Suit of Wands: Skills of Energy and Influence","pageTitle":"skills","breadcrumb":"skills › Suit of Wands: Skills of Energy and Influence","url":"/generators/tarot/skills/#suit-of-wands-skills-of-energy-and-influence","content":"Ace of Wands - Upright: Fire-Starting. Expert skill in wilderness survival, pyrotechnics, or smithing. - Reversed: Panic-Inducing. The skill of creating a frantic, high-energy distraction. Two of Wands - Upright: Cartography. The skill of reading, making, and navigating complex maps. - Reversed: Local Recon. Expert knowledge of a specific, small-scale territory. Three of Wands - Upright: Ship-Mastery. Skill in naval navigation, maritime law, or overseas trade. - Reversed: Long-Range Scouting. Identifying threats before they reach the camp. Four of Wands - Upright: Event Coordination. Organizing safe-houses, festivals, or social retreats. - Reversed: Barrier-Breaching. The skill of \"crashing\" a secure party or celebration. Five of Wands - Upright: Crowd Fighting. Skill in handling multiple opponents in a chaotic brawl. - Reversed: Mediation. The skill of de-escalating a physical fight before it starts. Six of Wands - Upright: Public Relations. The skill of \"spinning\" a story to make som","description":"","headingLevel":2,"fileSlug":"skills"},{"title":"Suit of Wands: Skills of Presence and Command","pageTitle":"skills","breadcrumb":"skills › Suit of Wands: Skills of Presence and Command","url":"/generators/tarot/skills/#suit-of-wands-skills-of-presence-and-command","content":"Page of Wands - Upright: Trend-Setting. The skill of identifying and launching a new social movement or fashion. - Reversed: Distraction-Artistry. Using loud, colorful energy to divert attention from a crime. Knight of Wands - Upright: Stunt-Work. Expert skill in high-risk physical maneuvers and combat mobility. - Reversed: Provocation. Knowing exactly how to goad an enemy into making a fatal, angry mistake. Queen of Wands - Upright: Social Magnetism. The skill of commanding a room and making others work for your approval. - Reversed: Intimidation. Using sheer force of personality to make others back down without a fight. King of Wands - Upright: Visionary Leadership. The skill of building a massive organization or empire from scratch. - Reversed: Command Authority. The ability to give orders that people obey instinctively, even in terror.","description":"","headingLevel":2,"fileSlug":"skills"},{"title":"traits","pageTitle":"traits","breadcrumb":"traits","url":"/generators/tarot/traits/","content":"","description":"","headingLevel":1,"fileSlug":"traits"},{"title":"Major Arcana: Core Personality Traits","pageTitle":"traits","breadcrumb":"traits › Major Arcana: Core Personality Traits","url":"/generators/tarot/traits/#major-arcana-core-personality-traits","content":"0 The Fool - Upright: Spontaneous. Lives entirely in the \"now\" without a care for the past. - Reversed: Reckless. Ignores red flags and warnings to their own detriment. I The Magician - Upright: Resourceful. Always finds a way to use the tools at hand. - Reversed: Deceptive. Naturally prone to \"smoke and mirrors\" to get their way. II The High Priestess - Upright: Intuitive. Deeply attuned to things that aren't being said. - Reversed: Withdrawn. Keeps so many secrets that they become unreachable. III The Empress - Upright: Nurturing. Has a biological or emotional need to care for others. - Reversed: Smothering. Cannot allow others to have independence or breathe. IV The Emperor - Upright: Authoritative. Commands respect through logic, order, and presence. - Reversed: Rigid. Incapable of changing their mind once a \"rule\" is set. V The Hierophant - Upright: Traditional. Finds safety and identity in established institutions. - Reversed: Iconoclastic. Driven by a need to tear down existing ","description":"","headingLevel":2,"fileSlug":"traits"},{"title":"**Suit of Cups: Traits of Emotion and Connection**","pageTitle":"traits","breadcrumb":"traits › **Suit of Cups: Traits of Emotion and Connection**","url":"/generators/tarot/traits/#suit-of-cups-traits-of-emotion-and-connection","content":"Ace of Cups - Upright: Openhearted. Approaches the world with genuine, raw kindness. - Reversed: Guarded. Has \"locked\" their heart away behind thick emotional walls. Two of Cups - Upright: Affectionate. Naturally seeks out deep, one-on-one connections. - Reversed: Disharmonious. Prone to \"push-pull\" dynamics in relationships. Three of Cups - Upright: Gregarious. Thrives in large groups and shared emotional experiences. - Reversed: Superficial. Values \"party friends\" over real, deep connections. Four of Cups - Upright: Contemplative. Prone to long periods of quiet, internal reflection. - Reversed: Discontent. Perpetually bored, regardless of how much they have. Five of Cups - Upright: Sentimental. Places immense value on memories and emotional history. - Reversed: Pessimistic. Focused entirely on what they have lost rather than what remains. Six of Cups - Upright: Whimsical. Retains a child-like sense of wonder and playfulness. - Reversed: Stuck. Refuses to grow up or acknowledge the pa","description":"","headingLevel":2,"fileSlug":"traits"},{"title":"Suit of Cups: Traits of Sensitivity and Charm","pageTitle":"traits","breadcrumb":"traits › Suit of Cups: Traits of Sensitivity and Charm","url":"/generators/tarot/traits/#suit-of-cups-traits-of-sensitivity-and-charm","content":"Page of Cups - Upright: Dreamy. Possesses a quiet, poetic, and slightly magical outlook on life. - Reversed: Over-Sensitive. Takes every minor social cue as a profound personal attack. Knight of Cups - Upright: Chivalrous. Driven by a high moral code and a desire for \"pure\" connections. - Reversed: Fickle. Constantly \"falling in love\" with new ideas or people, then quitting. Queen of Cups - Upright: Compassionate. Has a \"soul-deep\" ability to listen and hold space for others. - Reversed: Unstable. Projecting their internal emotional \"storms\" onto everyone around them. King of Cups - Upright: Diplomatic. Capable of navigating the most volatile social waters with ease. - Reversed: Withdrawn. Using emotional distance as a weapon to maintain control.","description":"","headingLevel":2,"fileSlug":"traits"},{"title":"**Suit of Pentacles: Traits of Body and Materiality**","pageTitle":"traits","breadcrumb":"traits › **Suit of Pentacles: Traits of Body and Materiality**","url":"/generators/tarot/traits/#suit-of-pentacles-traits-of-body-and-materiality","content":"Ace of Pentacles - Upright: Grounded. Solid, practical, and deeply connected to the physical world. - Reversed: Greedy. Views the world as a series of things to be owned. Two of Pentacles - Upright: Versatile. Can adapt their personality to fit any situation. - Reversed: Disorganized. A \"chaotic\" presence that leaves a mess in their wake. Three of Pentacles - Upright: Diligent. Takes immense pride in their work and craftsmanship. - Reversed: Unprofessional. Disrespectful of craft, rules, or mastery. Four of Pentacles - Upright: Possessive. Deeply protective of their time, money, and space. - Reversed: Miserly. Fearful of losing even a single cent or scrap of status. Five of Pentacles - Upright: Hardy. Has survived extreme lack and is physically \"tough.\" - Reversed: Scarcity-Minded. Always thinks the world is about to run out of \"enough.\" Six of Pentacles - Upright: Generous. Naturally shares resources, time, and advice. - Reversed: Patronizing. Helpful only because it makes them feel s","description":"","headingLevel":2,"fileSlug":"traits"},{"title":"Suit of Pentacles: Traits of Practicality and Reliability","pageTitle":"traits","breadcrumb":"traits › Suit of Pentacles: Traits of Practicality and Reliability","url":"/generators/tarot/traits/#suit-of-pentacles-traits-of-practicality-and-reliability","content":"Page of Pentacles - Upright: Studious. Quietly and carefully builds their life through hard work. - Reversed: Materialistic. Values people based solely on their physical worth or rank. Knight of Pentacles - Upright: Methodical. The \"slow and steady\" personality who never misses a detail. - Reversed: Stubborn. Refuses to change their mind, even when faced with proof they are wrong. Queen of Pentacles - Upright: Gracious. Radiates a sense of \"abundance\" and makes everyone feel taken care of. - Reversed: Possessive. Treats their friends, family, and objects as \"acquisitions.\" King of Pentacles - Upright: Stable. A \"pillar of the community\" who provides a sense of safety to others. - Reversed: Hedonistic. Focused entirely on physical comfort, wealth, and status symbols.","description":"","headingLevel":2,"fileSlug":"traits"},{"title":"**Suit of Swords: Traits of Mind and Logic**","pageTitle":"traits","breadcrumb":"traits › **Suit of Swords: Traits of Mind and Logic**","url":"/generators/tarot/traits/#suit-of-swords-traits-of-mind-and-logic","content":"Ace of Swords - Upright: Lucid. Possesses a terrifyingly clear and direct mind. - Reversed: Confused. Perpetually \"foggy\" and unable to grasp simple truths. Two of Swords - Upright: Neutral. The ultimate \"fence-sitter\" who sees both sides of every war. - Reversed: Indecisive. Paralyzed by the fear of making the \"wrong\" choice. Three of Swords - Upright: Melancholic. Carries a deep, poetic sadness as a core trait. - Reversed: Bitter. Uses their old wounds as an excuse to hurt others. Four of Swords - Upright: Serene. Has a \"monk-like\" ability to remain calm in a crisis. - Reversed: Burnt-out. Possesses zero mental or emotional energy reserves. Five of Swords - Upright: Ruthless. Driven by a \"win at all costs\" mentality. - Reversed: Humiliated. Carries a permanent sense of being \"lesser\" than others. Six of Swords - Upright: Logical. Views life as a series of navigational problems to be solved. - Reversed: Burdened. Mentally \"stuck\" in a toxic situation they won't leave. Seven of Swords ","description":"","headingLevel":2,"fileSlug":"traits"},{"title":"Suit of Swords: Traits of Wit and Precision","pageTitle":"traits","breadcrumb":"traits › Suit of Swords: Traits of Wit and Precision","url":"/generators/tarot/traits/#suit-of-swords-traits-of-wit-and-precision","content":"Page of Swords - Upright: Curious. A \"natural student\" who asks the questions no one else thinks of. - Reversed: Cynical. Believes everyone has a hidden, dirty motive for everything. Knight of Swords - Upright: Direct. Cuts through \"small talk\" and fluff to get straight to the truth. - Reversed: Fanatical. So obsessed with being \"right\" that they become hostile. Queen of Swords - Upright: Incisive. Possesses a sharp, dry wit and an ironclad sense of logic. - Reversed: Cold. Has \"cut off\" their emotions so thoroughly they lack basic empathy. King of Swords - Upright: Principled. Values the \"rule of law\" and intellectual honesty above all. - Reversed: Ruthless. Uses their intelligence to systematically dismantle their rivals.","description":"","headingLevel":2,"fileSlug":"traits"},{"title":"Suit of Wands: Traits of Charisma and Will","pageTitle":"traits","breadcrumb":"traits › Suit of Wands: Traits of Charisma and Will","url":"/generators/tarot/traits/#suit-of-wands-traits-of-charisma-and-will","content":"Page of Wands - Upright: Enthusiastic. Approaches every new idea with contagious, raw excitement. - Reversed: Aimless. Full of \"fire\" but lacks a chimney; loud but lacks a point. Knight of Wands - Upright: Fearless. Possesses a \"heroic\" level of confidence and physical bravery. - Reversed: Reckless. Habitually rushes into danger without a plan or an exit. Queen of Wands - Upright: Radiating. Naturally commands attention and makes others feel seen. - Reversed: Vain. Obsessed with being the most important or admired person in the room. King of Wands - Upright: Inspirational. A natural leader who motivates others through shared vision. - Reversed: Overbearing. Uses their strong personality to drown out everyone else’s voice.","description":"","headingLevel":2,"fileSlug":"traits"},{"title":"Suit of Wands: Traits of Vitality and Ego","pageTitle":"traits","breadcrumb":"traits › Suit of Wands: Traits of Vitality and Ego","url":"/generators/tarot/traits/#suit-of-wands-traits-of-vitality-and-ego","content":"Ace of Wands - Upright: Energetic. Possesses a constant, buzzing drive to start something new. - Reversed: Listless. Lacks the \"spark\" required to care about their own life. Two of Wands - Upright: Bold. Not afraid to look at a horizon and claim it as theirs. - Reversed: Hesitant. Paralyzed by the scale of their own possibilities. Three of Wands - Upright: Visionary. Always thinking three steps ahead of everyone else. - Reversed: Detached. So focused on the future they forget to live in the present. Four of Wands - Upright: Jovial. The \"life of the party\" who thrives on community joy. - Reversed: Anti-Social. Actively avoids celebrations or shared milestones. Five of Wands - Upright: Competitive. Views every conversation as a sport to be won. - Reversed: Conflict-Averse. Shuts down completely at the first sign of friction. Six of Wands - Upright: Confident. Carries themselves with the air of a natural victor. - Reversed: Needy. Requires constant external praise to feel any self-worth. ","description":"","headingLevel":2,"fileSlug":"traits"},{"title":"Glossary","pageTitle":"Glossary","breadcrumb":"Glossary","url":"/glossary/","content":"","description":"","headingLevel":1,"fileSlug":"glossary"},{"title":"A","pageTitle":"Glossary","breadcrumb":"Glossary › A","url":"/glossary/#a","content":"Advantage: when rolling with advantage, you roll two dice and take the highest result.","description":"","headingLevel":2,"fileSlug":"glossary"},{"title":"D","pageTitle":"Glossary","breadcrumb":"Glossary › D","url":"/glossary/#d","content":"DC: the number to roll above when deciding a success or fail of a given task or check. Typically stands for Difficulty Class. Descriptor: a word that describes your character, a trait or some other attribute that can be used as a tag to ease or hinder any appropriate roll. Disadvantage: when rolling with disadvantage, you roll two dice and thake the lowest result.","description":"","headingLevel":2,"fileSlug":"glossary"},{"title":"E","pageTitle":"Glossary","breadcrumb":"Glossary › E","url":"/glossary/#e","content":"Ease: to lower the level of a task/check resulting in a lower DC.","description":"","headingLevel":2,"fileSlug":"glossary"},{"title":"F","pageTitle":"Glossary","breadcrumb":"Glossary › F","url":"/glossary/#f","content":"Flaw: an attribute that describes an aspect of the character that could be considered bad. A flaw is a tag that can be uses to ease or hinder any appropriate roll.","description":"","headingLevel":2,"fileSlug":"glossary"},{"title":"H","pageTitle":"Glossary","breadcrumb":"Glossary › H","url":"/glossary/#h","content":"Hinder: to raise the level of a task/check resulting in a lower DC.","description":"","headingLevel":2,"fileSlug":"glossary"},{"title":"S","pageTitle":"Glossary","breadcrumb":"Glossary › S","url":"/glossary/#s","content":"Species: a word or phrase that defines a characters birth attributes such as elf, dwarf or even more specific as a shadow elf. Species can be used as a tag to ease and hinder any appropriate roll.","description":"","headingLevel":2,"fileSlug":"glossary"},{"title":"T","pageTitle":"Glossary","breadcrumb":"Glossary › T","url":"/glossary/#t","content":"Tag: a tag is a word or phrase that describes the character. A tag can be used to ease or hinder any appropriate roll. Task Threshold: Task Threshold is the maximum number of sources (tags, gear, aid, environment) that may be applied to ease a task. Type: a word or phrase that describes your characters career path, in other TTRPGs this would be their class or background or some other defining feature. A type is used as a tag to ease or hinder any appropriate roll.","description":"","headingLevel":2,"fileSlug":"glossary"},{"title":"U","pageTitle":"Glossary","breadcrumb":"Glossary › U","url":"/glossary/#u","content":"Umbrella Tag: All tags in the character sentence are considered Umbrella tags. These tags have a series of other tags that they embody. And if a player can logically explain reasons an umbrella tag can be used for to ease or hinder that action. ^6ca8a3","description":"","headingLevel":2,"fileSlug":"glossary"},{"title":"W","pageTitle":"Glossary","breadcrumb":"Glossary › W","url":"/glossary/#w","content":"Wound: a disadvantage taken after dropping a creature to zero harm. Wounds can be physical or mental, permanent or temporary depending on how they were received.","description":"","headingLevel":2,"fileSlug":"glossary"},{"title":"Character Advancement","pageTitle":"Character Advancement","breadcrumb":"Character Advancement","url":"/guides/advancement/","content":"Characters change through resolved quests. Minor changes, new information, temporary tags, altered relationships, can occur frequently. Major changes, new capabilities, removed limitations, tier increases, only occur when a quest or personal quest is meaningfully resolved. Advancement is narrative, not incremental. Characters do not grow because they succeed often, but because they confront situations that force transformation. If a quest does not change the character, it was not personal. Completing or failing quests may alter a character’s tags, relationships, or arc.","description":"","headingLevel":1,"fileSlug":"advancement"},{"title":"Procedure","pageTitle":"Character Advancement","breadcrumb":"Character Advancement › Procedure","url":"/guides/advancement/#procedure","content":"Characters grow laterally. However, tags can increase in tier through quests or use. If you roll a 1 or 20 when using a tag in any task (not an oracle check) 5 five times you can increase your tier by 1 then reset the count to zero. The max tier is 4. Mastery of a skill or ability can come from failure or absolute success. Though the success on the 20 doesn't necessarily mean the action succeeded.","description":"","headingLevel":2,"fileSlug":"advancement"},{"title":"Character Creation","pageTitle":"Character Creation","breadcrumb":"Character Creation","url":"/guides/character/","content":"A Character in Tag & Tally is a collection of tags that can ease or hinder game play.","description":"","headingLevel":1,"fileSlug":"character"},{"title":"Adolescence (11-18)","pageTitle":"Character Creation","breadcrumb":"Character Creation › Life Stage Tags › Adolescence (11-18)","url":"/guides/character/#adolescence-11-18","content":"Background Tag: Defining adolescent experience. Flaw Tag : Personality flaw emerging in adolescence. Additional Tags: Skills, traits, or habits formed during adolescence.","description":"","headingLevel":3,"fileSlug":"character"},{"title":"Adult (26-50)","pageTitle":"Character Creation","breadcrumb":"Character Creation › Advanced Options › Adult (26-50)","url":"/guides/character/#adult-26-50","content":"Occupation Tag: Main profession or life role. - Optional Career Change Tags (up to 5 total careers in a lifetime): Additional occupation tags if changing careers Or tier up your existing career up to tier 4 Flaw Tag: Personality flaw or challenge in adulthood. Additional Tags (2 per 5-year block): Skills, traits, or experiences. Structure: | Age Range | Occupation | Flaw | Additional | | --------- | ---------- | ---- | ---------- | | 26-30 | +1 | +1 | +2 | | 31-35 | +1\\ | +1 | +2 | | 36-40 | +1\\ | +1 | +2 | | 41-45 | +1\\ | +1 | +2 | | 46-50 | +1\\ | +1 | +2 | \\* Optional if Career change otherwise can increase Tier of the Tag up to 4","description":"","headingLevel":3,"fileSlug":"character"},{"title":"Advanced Options","pageTitle":"Character Creation","breadcrumb":"Character Creation › Advanced Options","url":"/guides/character/#advanced-options","content":"If you want a much older character we have rules for that. While you know more, and learn more, you also have a lot more flaws as you advance with age. So keep that in mind when using these rules.","description":"","headingLevel":2,"fileSlug":"character"},{"title":"Appearance (Optional)","pageTitle":"Character Creation","breadcrumb":"Character Creation › Appearance (Optional)","url":"/guides/character/#appearance-optional","content":"When detailing a character's appearance, you may roll or choose from the Character tables: pronoun, age, distinguishing feature type, skin tone, complexion, build/height, hair (texture, style, color), eye color, clothing, and voice.","description":"","headingLevel":2,"fileSlug":"character"},{"title":"Character Arcs","pageTitle":"Character Creation","breadcrumb":"Character Creation › Character Arcs","url":"/guides/character/#character-arcs","content":"Characters should start with a Character Arc — something they are trying to achieve. Character Arcs should reward a new tag at the completion of its arc relative to what the arc was trying to achieve. It may offer other rewards as well depending on what the arc was meant to achieve. On the character sheet, character arcs are recorded under Quests (one quest per arc); there is no separate \"Character Arcs\" section on the sheet.","description":"","headingLevel":2,"fileSlug":"character"},{"title":"Character Sentence","pageTitle":"Character Creation","breadcrumb":"Character Creation › Character Sentence","url":"/guides/character/#character-sentence","content":"We lay out your character sentence in the following format, and all tags are in square brackets. !character Character Name is a \\descriptor\\ \\species\\ \\type\\ who \\specializes in\\ All tags except descriptor in your character sentence are Umbrella Tags. - Eldrin is a cunning elven rogue who weaves shadows into deadly blades - Lena is a resourceful private investigator who uncovers secrets. - Vex-7 is a rogue AI bounty hunter who tracks fugitives. - Dr. Alistair Cogsworth is an eccentric clockwork engineer who builds automatons. This sentence defines the characters at a high level detail. Each of the words in the brackets are tags that describe your character. They can be used to ease or hinder an action check. Descriptors should define a key personality trait or something about the character that is a basic essence of the character. This can be good or bad, it is your character. Species is just what it is. In an all human world or for a human character choose a second descriptor to fill ","description":"","headingLevel":2,"fileSlug":"character"},{"title":"Childhood (0-10)","pageTitle":"Character Creation","breadcrumb":"Character Creation › Life Stage Tags › Childhood (0-10)","url":"/guides/character/#childhood-0-10","content":"Background Tag: Defining moment of childhood. Flaw Tag: Personality flaw shaped by early life. Additional Tags (up to 2): Early abilities, traits, or learned habits.","description":"","headingLevel":3,"fileSlug":"character"},{"title":"Elder (51+)","pageTitle":"Character Creation","breadcrumb":"Character Creation › Advanced Options › Elder (51+)","url":"/guides/character/#elder-51","content":"Flaw Tag (1 per 10 year block): Reflecting aging, limitations, or consequences of life choices. Experience Tag (1 per 10 year block): Reflecting wisdom, mastery, or societal reputation. Structure: | Age Range | Flaw | Experience | | --------- | ---- | ---------- | | 51-60 | +1 | +1 | | 61-70 | +1 | +1 | | 71-80 | +1 | +1 | | 81-90\\ | +1 | +1 | \\ Continue pattern for additional age ranges","description":"","headingLevel":3,"fileSlug":"character"},{"title":"Gear & Wealth","pageTitle":"Character Creation","breadcrumb":"Character Creation › Gear & Wealth","url":"/guides/character/#gear-wealth","content":"Characters can carry up to ten items and have a starting Wealth of 3. The Inventory Module has other methods for gear and character creation, but no matter how you handle inventory your character will start with the same basic equipment loadout. While creating the items you should roll 1d6 to determine the level of the item unless otherwise stated. 1 weapon of choice 1 armor of choice — typical chest piece for zone loadouts 1 specialized piece of gear — linked to your type or specialty 1 communication/utility device — a smartphone, a lantern, etc 3 addition items of choice 1 Personal Memento Fixed at Level 1 1 Flaw-breaker item — optional Level 10 mini-quest backstory item to overcome a flaw Characters may have narrative containers to organize their work. They do not take up a slot, nor do they count against starting items. But they are purely for narrative purposes. And are not necessary. You may choose to list your pocket as a container so you know your smartphone is in it with your ","description":"","headingLevel":2,"fileSlug":"character"},{"title":"Group Play","pageTitle":"Character Creation","breadcrumb":"Character Creation › Group Play","url":"/guides/character/#group-play","content":"If playing with a group either as individual players or as a solo player, the group should figure out how they know each other. It can be helpful to think about how they met, and why they are all together. You can also assign each character a relationship status to remind you how your characters interact with one another.","description":"","headingLevel":2,"fileSlug":"character"},{"title":"Known World Lore","pageTitle":"Character Creation","breadcrumb":"Character Creation › Known World Lore","url":"/guides/character/#known-world-lore","content":"Assume all player characters know two locations. Their residence Their place of employ or similar location A character's background, or place of employment (such as city government or a bounty hunter association), may determine their starting faction. The character should have a starting relationship with their faction that is up to two steps from indifferent. A character may have up to three known NPCs (family, employers, contacts, etc.). Assign each known NPC a relationship status up to three steps away from indifferent.","description":"","headingLevel":2,"fileSlug":"character"},{"title":"Life Stage Tags","pageTitle":"Character Creation","breadcrumb":"Character Creation › Life Stage Tags","url":"/guides/character/#life-stage-tags","content":"There are 5 life stages of a character: childhood, adolescence, young adult, adult and elder. Each stage has a number of tags you are required to choose upon character creation based on the age of your character. All ages are based on human years. Check the species for age ranges of your character. There are a number of different tags for each life stage: background, flaw, occupation, experience and additional tags. Background Tags: Background tags describe a defining moment in that Life Stage. Flaw Tags: Flaw Tags describe some flaw or weakness they displayed during this Life Stage of the character. It might be helpful to assign the flaw to one of the seven deadly sins. As an Elder these flaw tags should be in reference to getting older. Things like \"Losing Mobility\" and \"Hearing Loss\". Occupation Tags: Occupation Tags are tags that encompass what you do for a living at that particular Life Stage. As a young adult you may choose \"Student\" or some other career. But as an Adult you must","description":"","headingLevel":2,"fileSlug":"character"},{"title":"Optional Level 10 with Mini-Quest Backstory","pageTitle":"Character Creation","breadcrumb":"Character Creation › Gear & Wealth › Optional Level 10 with Mini-Quest Backstory","url":"/guides/character/#optional-level-10-with-mini-quest-backstory","content":"In addition to these starting items a player may opt to give a character a level 10 passive item that overcomes a flaw. If the character wishes to have this they need to complete a back story question and make it part of their story. There are a few options how to do it. Write a narrative Play a flashback with the group Play a solo mode quest Each of these methods must answer the following questions: What flaw are you trying to overcome? This should be one of the flaw tags you added during character creation. What is the item you are trying to gain, and what does it do? This item should have an item sentence will be Level 10 and can stablize or ease actions hindered by your flaw by 2. How are you going to obtain the item? Make it Myself Purchase from a vendor Quest for the Item The Solo Quest Loop In solo mode, you play through the following sequence. Each success or failure answers a narrative question about the character's journey. Question A: What is the \"Entry Price\"? Action: Negot","description":"","headingLevel":3,"fileSlug":"character"},{"title":"Procedure","pageTitle":"Character Creation","breadcrumb":"Character Creation › Procedure","url":"/guides/character/#procedure","content":"Follow the following simple steps to create a character. It is recommended to create a Young Adult or Adult character for best options. Create a concept of what you want your character to be and do. Design the character sentence around this concept. Choose your Childhood Life Stage tags (1 background, 1 flaw, 2 additional tags) Choose your Adolesent Life Stage tags (1 background, 1 flaw, 2 additional tags) Choose your Young Adult Life Stage tags (1 background, 1 occupation, 1 flaw, 2 additional tags) Assign Skill Tiers to your Tags, and if they are a spell caster, MAI and Tier Create a character arc for your character -- their purpose for adventuring. A character are is a personal quest. Decide upon what gear your character will start out with Choose what lore a character knows at the start of the game (locations, factions and personal relationships). (optional) If in a party, decide upon the relationships between all party members and how you met.","description":"","headingLevel":2,"fileSlug":"character"},{"title":"Skill Teirs","pageTitle":"Character Creation","breadcrumb":"Character Creation › Advanced Options › Skill Teirs","url":"/guides/character/#skill-teirs","content":"Characters staring as an Adult assign the Young Adult Tiers and then add 6 points per 5 year block after 25 Characters starting as an Elder assign the Young Adult Tiers, add 30 points plus an additional 4 points per 10 year block Adults and Elders can assign their points to tiers in the following manner: | Tier | Point Cost | | ---- | ---------- | | 2 | 2 | | 3 | 4 | | 4 | 6 | Each Tier must be bought before purchasing the next. If you have a tag at level 1 and you want it to be level 4 you need to purchase 2, 3 and 4 for a total of 12 points. Use this method ONLY at character creation! Skills are earned and upgraded during game play by finishing quests and character arc as rewards. Any unused points at character creation are lost.","description":"","headingLevel":3,"fileSlug":"character"},{"title":"Skill Tiers","pageTitle":"Character Creation","breadcrumb":"Character Creation › Skill Tiers","url":"/guides/character/#skill-tiers","content":"Characters starting as a Child may have 1 Tier 2 abilities (2 points) Characters starting as an Adolescent many have 2 Tier 2 abilities (4 points) Characters starting as a Young Adult may have 1 Tier 3 ability, 2 Tier 2 abilities (10 points) Optionally you may start with the number of points assigned to the Life Stage (the number in parenthesis) and create your own breakout. | Tier | Point Cost | | ---- | ---------- | | 2 | 2 | | 3 | 4 | | 4 | 6 | Each Tier must be bought before purchasing the next. If you have a tag at level 1 and you want it to be level 4 you need to purchase 2, 3 and 4 for a total of 12 points. Use this method ONLY at character creation! Skills are earned and upgraded during game play by finishing quests and character arc as rewards. Any unused points at character creation are lost.","description":"","headingLevel":2,"fileSlug":"character"},{"title":"Young Adult (19-25)","pageTitle":"Character Creation","breadcrumb":"Character Creation › Life Stage Tags › Young Adult (19-25)","url":"/guides/character/#young-adult-19-25","content":"Background Tag: Defining life-changing event or experience. Occupation Tag: Current occupation or primary life role (job, apprenticeship, or student). Flaw Tag: Flaw tied to ambition, independence, or early mistakes. Additional Tags: Skills, habits, or traits developed in young adulthood.","description":"","headingLevel":3,"fileSlug":"character"},{"title":"Creature Creation","pageTitle":"Creature Creation","breadcrumb":"Creature Creation","url":"/guides/creature/","content":"A Creature in Tag & Tally is a collection of tags that can ease or hinder game play.","description":"","headingLevel":1,"fileSlug":"creature"},{"title":"Creature Sentence","pageTitle":"Creature Creation","breadcrumb":"Creature Creation › Creature Sentence","url":"/guides/creature/#creature-sentence","content":"We lay out your creature sentence in the following format, and all tags are in square brackets. !creature Creature Name (\\disposition \\descriptor \\type):This creature \\motivation and attacks with \\attack of choice for \\damage type damage. It features a unique ability to \\do something special. It \\has a strength and \\has a weakness. Disposition: should define how the creature behaves in most cases. Descriptors should define a key trait or something about the creature that is its basic essence. This can be good or bad. Type: should define the general type of the creature. Types can vary by setting. Motivation: should define what drives the creatures instincts. Damage Type should be one of the allowed damage types in the setting. Attach of Choice should be how they do their main damage. ie: with a weapon, a specific spell, their claws, etc. Strength should be what the creature excels at. Weakness should be something that a player can take advantage of to defeat it. Strengths and Weaknesse","description":"","headingLevel":2,"fileSlug":"creature"},{"title":"Procedure","pageTitle":"Creature Creation","breadcrumb":"Creature Creation › Procedure","url":"/guides/creature/#procedure","content":"Follow the following simple steps to create a creature. Create a concept of what you want the creature to be. Design the creature sentence around this concept. - All creatures have a strength and weakness - All creatures can do something special - All creatures have a basic attack with damage type - All creatures have some type of motivation that drives their actions Write a description of the creature The level of the creature is equal to the level of the scene or hex they are found in.","description":"","headingLevel":2,"fileSlug":"creature"},{"title":"Example Game Loop","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop","url":"/guides/example-loop/","content":"","description":"","headingLevel":1,"fileSlug":"example-loop"},{"title":"Active External Quest","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Active External Quest","url":"/guides/example-loop/#active-external-quest","content":"Quest: Discover who is smuggling relics through the river docks","description":"","headingLevel":2,"fileSlug":"example-loop"},{"title":"Apply Consequences","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Step 5: Establish Stakes › Apply Consequences","url":"/guides/example-loop/#apply-consequences","content":"Quest update: - The investigation quest advances sideways; the smugglers are now alert Insight update: - Ilya gains a partial and risky insight instead of a clean one Character change: - Temporary tag added: Marked by the Smugglers","description":"","headingLevel":3,"fileSlug":"example-loop"},{"title":"Carry Forward","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Step 5: Establish Stakes › Carry Forward","url":"/guides/example-loop/#carry-forward","content":"Future dock scenes may justify higher opposition or predefined threat levels Ilya’s personal quest is pressured; reputation risk increases The scene ends because the original intent is meaningfully altered.","description":"","headingLevel":3,"fileSlug":"example-loop"},{"title":"Character","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Character","url":"/guides/example-loop/#character","content":"Name: Ilya Personal Quest: Prove I am more than my family’s reputation Relevant Tags: - Trained Investigator - Known to the Dockworkers - Haunted by a Past Failure","description":"","headingLevel":2,"fileSlug":"example-loop"},{"title":"First Action","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Step 5: Establish Stakes › First Action","url":"/guides/example-loop/#first-action","content":"Action: Quietly question dockworkers while observing traffic. Base difficulty: Scene Level 5 Relevant tags: - Known to the Dockworkers (eases the task) * Cold Rain (hinders careful observation) The effects cancel out. Difficulty remains 5. Roll Result: Partial success Outcome: Ilya learns that a specific boat has been unloading at odd hours Someone notices his questions Escalation: Suspicion is introduced into the scene.","description":"","headingLevel":3,"fileSlug":"example-loop"},{"title":"Second Action","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Step 5: Establish Stakes › Second Action","url":"/guides/example-loop/#second-action","content":"Because the intent is not yet achieved and consequences escalated, another action is required. Action: Follow the identified boat without being seen. Difficulty: 5 Additional pressure: - Someone is watching (from the scene sentence) Tag applied: - Haunted by a Past Failure (hinders composure) Roll Result: Failure","description":"","headingLevel":3,"fileSlug":"example-loop"},{"title":"Step 1: Roll a Scene Level","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Step 1: Roll a Scene Level","url":"/guides/example-loop/#step-1-roll-a-scene-level","content":"This is not the first scene of play. The previous scene was Level 4. Dice formula: 1d6 + 2 Roll: 3 + 2 = Scene Level 5 The docks are moderately dangerous, tense, and active.","description":"","headingLevel":2,"fileSlug":"example-loop"},{"title":"Step 2: (Optional) Roll a Scene Sentence","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Step 2: (Optional) Roll a Scene Sentence","url":"/guides/example-loop/#step-2-optional-roll-a-scene-sentence","content":"Rolled result: “Someone is watching, but it’s not clear who.” This informs tone but does not impose mechanics yet.","description":"","headingLevel":2,"fileSlug":"example-loop"},{"title":"Step 3: Additional Scene Modifiers","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Step 3: Additional Scene Modifiers","url":"/guides/example-loop/#step-3-additional-scene-modifiers","content":"The player selects the following modifiers: Time of day: Late night Weather: Cold rain These elements shape the fiction and may justify tags.","description":"","headingLevel":2,"fileSlug":"example-loop"},{"title":"Step 4: Declare Intent","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Step 4: Declare Intent","url":"/guides/example-loop/#step-4-declare-intent","content":"Immediate goal: Identify who is coordinating the smuggling operation tonight. Quest advanced or threatened: - Advances the smuggling investigation quest - Risks complicating Ilya’s personal quest if he fails publicly","description":"","headingLevel":2,"fileSlug":"example-loop"},{"title":"Step 5: Establish Stakes","pageTitle":"Example Game Loop","breadcrumb":"Example Game Loop › Step 5: Establish Stakes","url":"/guides/example-loop/#step-5-establish-stakes","content":"If successful: - Gain a solid insight identifying a key smuggler If failed: - The smugglers notice Ilya’s interest and take countermeasures","description":"","headingLevel":2,"fileSlug":"example-loop"},{"title":"GMless","pageTitle":"GMless","breadcrumb":"GMless","url":"/guides/gmless/","content":"Tag and Tally is meant to be played solo or in a gm-less way. When playing with multiple players it is important to have a structure to how the world reacts to you and the rest of the party. There are several methods to do this.","description":"","headingLevel":1,"fileSlug":"gmless"},{"title":"A New Narrator every X minutes","pageTitle":"GMless","breadcrumb":"GMless › A New Narrator every X minutes","url":"/guides/gmless/#a-new-narrator-every-x-minutes","content":"An alternative to the One Narrator per scene that allows everyone to get a shake at the role is to again roll that d20 decide the order. And then your estimated play time by the number of players. And then set a timer when the timer ends, it is time to switch narrators even if it's in the middle of some action. This can create some interesting tension and dynamics.","description":"","headingLevel":2,"fileSlug":"gmless"},{"title":"One Narrator Per Scene","pageTitle":"GMless","breadcrumb":"GMless › One Narrator Per Scene","url":"/guides/gmless/#one-narrator-per-scene","content":"This is my perferred method of managing. At the beginning of a session, everyone rolls a d20. The highest goes first, and then on down the line like initiative. Each scene there is one narrator, they control this scene creatures, npcs, the oracle final decisions, etc. The say what carries over from this scene to the next, and then the next player in line becomes the narrator and uses these details to set up the next scene.","description":"","headingLevel":2,"fileSlug":"gmless"},{"title":"One Narrator Per Session","pageTitle":"GMless","breadcrumb":"GMless › One Narrator Per Session","url":"/guides/gmless/#one-narrator-per-session","content":"Each session one of the players gets to make all the decisions of what the oracle and modifiers mean and they get to control all the monsters and NPCs actions. Then the next session another player takes a turn. This works if you are running a campagin with many sessions, or you are learning how to play the game from someone who has done it before.","description":"","headingLevel":2,"fileSlug":"gmless"},{"title":"Item Creation","pageTitle":"Item Creation","breadcrumb":"Item Creation","url":"/guides/items/","content":"An item in Tag & Tally is a collection of tags that can be used to ease or hinder game play.","description":"","headingLevel":1,"fileSlug":"items"},{"title":"Item Sentences","pageTitle":"Item Creation","breadcrumb":"Item Creation › Item Sentences","url":"/guides/items/#item-sentences","content":"There are various items in Tag & Tally, each having a slightly different sentence format. !item Item Name is a \\descriptor\\ \\item type\\ that \\does something special\\. !armor Armor Name is a \\descriptor\\ \\material\\ \\armor type\\ that \\does something special\\. !weapon Weapon Name is a \\descriptor\\ \\material\\ \\weapon type\\ that does \\damage type\\ damage and \\something special\\. !item Trap Name is a \\descriptor\\ \\trap type\\ that \\trigger condition\\ and \\effect or consequence\\. !item Consumable Name is a \\descriptor\\ \\consumable type\\ that \\effect on consumption\\ and \\any special property or twist\\.","description":"","headingLevel":2,"fileSlug":"items"},{"title":"Procedure","pageTitle":"Item Creation","breadcrumb":"Item Creation › Procedure","url":"/guides/items/#procedure","content":"Follow the following simple steps to create an item. Create a concept of what you want the item to be. Design the item sentence around this concept. Roll 1d10 to determine the level of the item.","description":"","headingLevel":2,"fileSlug":"items"},{"title":"NPC Creation","pageTitle":"NPC Creation","breadcrumb":"NPC Creation","url":"/guides/npc/","content":"An NPC in Tag & Tally is a collection of tags that can ease or hinder game play.","description":"","headingLevel":1,"fileSlug":"npc"},{"title":"NPC Sentence","pageTitle":"NPC Creation","breadcrumb":"NPC Creation › NPC Sentence","url":"/guides/npc/#npc-sentence","content":"We lay out your NPC sentence in the following format, and all tags are in square brackets. !character NPC Name is a \\descriptor \\species \\type who \\does something special. They are motivated \\a motivation and have a goal \\a goal. In combat, they deal \\damage type damage with \\attack of choice, but they \\have a secret. Descriptors should define a key personality trait or something about the NPC that is a basic essence of the NPC. This can be good or bad,.. Species is just what it is. In an all human world or for a human NPC choose a second descriptor to fill in the sentence. The species of a NPC can tell a lot about what society perceives the NPC as. In some cases it could also be used in tasks that a species might be good at. Include all species tags in your NPC sheet for easy reference under the species name. If you have a Psionic species. These NPCs are going to be really good with mental tasks, since that's what they're born to do. Mental tasks can be eased. But it also might make t","description":"","headingLevel":2,"fileSlug":"npc"},{"title":"Procedure","pageTitle":"NPC Creation","breadcrumb":"NPC Creation › Procedure","url":"/guides/npc/#procedure","content":"Follow the following simple steps to create an NPC. Create a concept of what you want the npc to be. Design the npc sentence around this concept. Give the NPC a flaw, occupation and a background. Pick a Damage type Roll a d10. This determines the NPCs Level and the number of skills, ablitites and traits they have in addition to the ones they gain from their sentence. An NPC may have up to their level in tiered abilities (ie: at level 10, 5 Tier 2 abilities, 3 Tier 3 abilities, 2 Tier 4 abilities and 1 Tier 2 ability, or any other combination totaling up to 10. Tier 1 abilities do not count.) Determine the basic information to help play the NPC","description":"","headingLevel":2,"fileSlug":"npc"},{"title":"Party Creation","pageTitle":"Party Creation","breadcrumb":"Party Creation","url":"/guides/party/","content":"When creating a party in Tag and Tally, whether in solo play or with a group there should always be connections.","description":"","headingLevel":1,"fileSlug":"party"},{"title":"Evolution of Bonds","pageTitle":"Party Creation","breadcrumb":"Party Creation › Evolution of Bonds","url":"/guides/party/#evolution-of-bonds","content":"As with character advancement some quests can alter the status of these bonds, changing the shared tag completely, or increasing its effective tier level. The Relationship type could also evolve, you could lose touch, or become rivals. All possible with in the real of the story.","description":"","headingLevel":2,"fileSlug":"party"},{"title":"History","pageTitle":"Party Creation","breadcrumb":"Party Creation › Party Creation › History","url":"/guides/party/#history","content":"Your relationship isn't just a label, it's a fact of your characters life. You need to create at least a 1 sentence summary of the relationship you have with each character. Once you and the other characters have agreed on a relationship, now you can create a Shared Benefit. This is a tag that can be used when you are both in the same party and it relates to the action at hand.","description":"","headingLevel":3,"fileSlug":"party"},{"title":"Party Creation","pageTitle":"Party Creation","breadcrumb":"Party Creation › Party Creation","url":"/guides/party/#party-creation","content":"Like all things in Tag and Tally a Party should have a sentence. !character Party Name is a \\descriptor \\group type who \\does something collectively. Descriptors should define a key personality trait or something about the character that is a basic essence of the character. This can be good or bad, it is your character. Group type should define the type of group your party is -- a guild, a merry band, a mercenary group, hunting party etc. Does Something collectively is what your group specializes in. This is a major defining action for your party. It can go hand in hand with the type, or it can be something completely off the wall and go against the types typical associations. This is what your party is known for or uses to their advantage. The phrase should always start with a verb. While is, can or has are perfectly acceptable ways to start the sentence, try looking for action verbs instead.","description":"","headingLevel":2,"fileSlug":"party"},{"title":"Relationship","pageTitle":"Party Creation","breadcrumb":"Party Creation › Party Creation › Relationship","url":"/guides/party/#relationship","content":"Each character during character creation must have at least one Personal Bond with at least one other character in the party. Each other character in the party must have a secondary connection (at minimum) of: Acquaintance, Rival or Friend of a Friend. You may have more than one Personal Bond with additional characters, it doesn't have to be just one. Relationship Types Personal Bond is a someone your character has a close personal relationship. They could be a friend, a family member, a mentor, someone who wronged you. This bond is partially why you are in the party. A Personal Bond eases your interactions by 2 with this character. (+2 mod for your character sheet) An acquaintance is someone your character has met in the past. An Acquaintance tag eases your interactions by 1 with this character. (+1 mod for your character sheet) A Rival is a character with whom your character shares a rivalry with. A Rival tag hinders your interactions by 1 with this character.. (-1 mod for your chara","description":"","headingLevel":3,"fileSlug":"party"},{"title":"How to Play","pageTitle":"How to Play","breadcrumb":"How to Play","url":"/guides/play/","content":"To start playing we need to answer a few questions. Where? Who? What and Why? We've shown you the answer to the question \"How?\" in the previous section.","description":"","headingLevel":1,"fileSlug":"play"},{"title":"Character Sentence","pageTitle":"How to Play","breadcrumb":"How to Play › Where? › Character Sentence","url":"/guides/play/#character-sentence","content":"!character Character Name is a \\descriptor\\ \\species\\ \\type\\ who \\specializes in\\ This sentence defines the characters at a high grain detail. Each of the words in the brackets are tags that describe your character. They can be used to ease or hinder an action check. Descriptors should define a key personality trait or something about the character that is a basic essence of the character. This can be good or bad, it is your character. Species is just what it is. In an all human world or for a human character choose a second descriptor to fill in the sentence. The species of a character can tell a lot about what society perceives the character as. In some cases it could also be used in tasks that a species might be good at. If you have a Psionic species. These characters are going to be really good with mental tasks, since that's what they're born to do. Mental tasks can be eased. But it also might make them vulnerable to psionics because they have a much more open mind. It's all about","description":"","headingLevel":3,"fileSlug":"play"},{"title":"How?","pageTitle":"How to Play","breadcrumb":"How to Play › How?","url":"/guides/play/#how","content":"The most important part -- have fun Now you have a quest for your characters to go on in the world you've created. But how do you start? The Mechanics Chapter contains all the basic rules you need for playing the game. First things first, figure out how you find the source of the quest. You can already know how you did that or you can ask the oracle. If you don't know something, as the oracle. Sometimes you need a better answer than Yes or No, or you need help interpreting the random keywords that the app gives you. Don't be afraid to consult other mediums for assistance. (Me personally, I like asking AI and using what I like from its suggestions to inspire the next thing.) This is your game, and you should play it how you want to. This is what I do.","description":"","headingLevel":2,"fileSlug":"play"},{"title":"Starting a Scene","pageTitle":"How to Play","breadcrumb":"How to Play › How? › Starting a Scene","url":"/guides/play/#starting-a-scene","content":"All Scenes should have a level starting at 3 and up to 10 depending on how difficult you want your game to be. In Solo play roll 1d4+2 to get the scene level between 3 and 6 which makes the scene non-trivial. A GM may assign each scene a level. Scenes may have various modifying tags assigned to it that always apply. Environmental Tags such a Rainy Day, Nighttime, and Rough Terrain are examples of tags that could be applied to a scene. In GM-less play, it might be beneficial to add a play order using either a round robin or highest to lowest roll on a d20 to determine order of acting questions to the oracle and setting up game dynamics. With a GM, the GM provides a description and the players react, the same play order may be used, or moderated by the GM, however is decided is best for the table.","description":"","headingLevel":3,"fileSlug":"play"},{"title":"The Oracle Method","pageTitle":"How to Play","breadcrumb":"How to Play › What and Why? › The Oracle Method","url":"/guides/play/#the-oracle-method","content":"If you have no idea start asking the Oracle questions. Some that are good to start with. Have the characters already met? Are the characters in a settlement? Do they have a mission? Do they work for anyone? These questions will lead to other questions and you can surmise a beginning to your story.","description":"","headingLevel":3,"fileSlug":"play"},{"title":"The Quest Method","pageTitle":"How to Play","breadcrumb":"How to Play › What and Why? › The Quest Method","url":"/guides/play/#the-quest-method","content":"Sometimes you there is a general theme you want to do or don't want to have to interpret as much as with the Oracle method. That's where the Quest Method comes in. You create a few random tables that help assist you in creating a decent quest idea that will help fuel the story forward. Quest need a set of things before you can begin. A starting location A source of the quest The type of quest it is What is the objective of the quest What is the reward? or Why are you doing the quest? Where is the objective of the quest found? Collect Antidote Ingredients Starting Location: Home Village Source: Village apothecary Type: Collection Objective: Collect the ingredients for the antidote Reward: A small bag of gold + Saving an NPC you need to speak to Location: Varies/Multiple","description":"","headingLevel":3,"fileSlug":"play"},{"title":"What and Why?","pageTitle":"How to Play","breadcrumb":"How to Play › What and Why?","url":"/guides/play/#what-and-why","content":"What is the purpose of the game Now that you have your characters and your setting it's time to think about what the character(s) are going to do. There are several methods you go could about doing this. I like The Oracle Method and the Quest Method.","description":"","headingLevel":2,"fileSlug":"play"},{"title":"Where?","pageTitle":"How to Play","breadcrumb":"How to Play › Where?","url":"/guides/play/#where","content":"Create a Setting or backdrop for the characters to exist in First thing we need to know is where are we going to be playing. You can use the tables to assist you in your thought process. Genre: Urban Fantasy - Modern World - Magic: Low Magic — magic exists but it is hard to come-by - Access: PCs have access, but most regular folks do not - Technology: High Technology — technology and science exist and are easy to come-by - Access: Everyone has access This sets the stage for what your characters can do. | Magic | Tech | Example Genres | | ---------- | --------- | -------------------------------------------------------------------------------------------- | | High Magic | No Tech | High Fantasy, Mythic Fantasy, Sword & Sorcery, Fairy Tale, Folk Horror | | High Magic | Low Tech | Heroic Fantasy, Dark Fantasy, Historical Fantasy, Wuxia, Arthurian Legend | | High Magic | High Tech | Magitech, Science Fantasy, Arcane Punk, Steampunk, Space Fantasy, Urban Fantasy | | Low Magic | No Tech | Low","description":"","headingLevel":2,"fileSlug":"play"},{"title":"Species Creation","pageTitle":"Species Creation","breadcrumb":"Species Creation","url":"/guides/species/","content":"Species are an umbrella tag with some special characteristics.","description":"","headingLevel":1,"fileSlug":"species"},{"title":"Procedure","pageTitle":"Species Creation","breadcrumb":"Species Creation › Procedure","url":"/guides/species/#procedure","content":"Create a species sentence Determine Languages Determine if species has innate magic and which types and what their Base MAI is. Assign a Weakness Determine 2 abilities/traits \\ \\ for each additional beyond 2 another weakness/flaw must be added","description":"","headingLevel":2,"fileSlug":"species"},{"title":"Sentence","pageTitle":"Species Creation","breadcrumb":"Species Creation › Procedure › Sentence","url":"/guides/species/#sentence","content":"!character Species This species is a \\aged \\descriptor\\ people who \\cultural trait or motivation\\ and \\physical/biological feature\\.","description":"","headingLevel":3,"fileSlug":"species"},{"title":"Creating a Spell","pageTitle":"Creating a Spell","breadcrumb":"Creating a Spell","url":"/guides/spell-creation/","content":"Spells are a simplified sentence but their core is built on following the procedure to determine the level of the spell.","description":"","headingLevel":1,"fileSlug":"spell-creation"},{"title":"Example Spells","pageTitle":"Creating a Spell","breadcrumb":"Creating a Spell › Procedure › Example Spells","url":"/guides/spell-creation/#example-spells","content":"Fireball Sentence: Fireball is a \\moderate \\Chaos spell that \\incinerates everything in its area. Aspect: Fire (moderate) → 2 points Type: Damage → 2 points Base: Chaos → 4 points Total: 2 + 2 + 4 = 8 → Level 3 Power Modifier: Medium distance / wider effect (street, hill) → 2 Final Spell Level: 3 + 2 = Level 5 Temporal Inferno (multiple axes) Sentence: Temporal Inferno is a \\volatile \\Chaos spell that \\burns and distorts time to damage and control enemies. Base: Chaos → 4 points Primary Aspect: Fire → 2 points Primary Type: Damage → 2 points Additional Aspect: Time → 3 points Additional Type: Control → 3 points Additional axis cost: 1st → 1, 2nd → 2 → 3 points total Total: 4 + 2 + 2 + 3 + 3 + 3 = 17 → Level 7 Power Modifier: Large distance / major area (town, city) → 3 Final Spell Level: 7 + 3 = Level 10","description":"","headingLevel":3,"fileSlug":"spell-creation"},{"title":"Level Mapping","pageTitle":"Creating a Spell","breadcrumb":"Creating a Spell › Procedure › Level Mapping","url":"/guides/spell-creation/#level-mapping","content":"| Total Points | Spell Level | | ------------ | ----------- | | 4–5 | 1 | | 6–7 | 2 | | 8–9 | 3 | | 10–11 | 4 | | 12–13 | 5 | | 14–15 | 6 | | 16–17 | 7 | | 18–19 | 8 | | 20–21 | 9 | | 22+ | 10 |","description":"","headingLevel":3,"fileSlug":"spell-creation"},{"title":"Point Values","pageTitle":"Creating a Spell","breadcrumb":"Creating a Spell › Procedure › Point Values","url":"/guides/spell-creation/#point-values","content":"Aspect and Type are called an axis; every spell has 2 axes as a base (one aspect and one type). | Aspect | Points | | ---------------------------------------------- | ------ | | earth, air, water, death, illusion (low-risk) | 1 | | fire, mind, light, sound (moderate) | 2 | | shadow, time, life, space (high-risk/volatile) | 3 | | Type | Points | | Base | Points | | ------- | ------ | --- | ------ | ------ | | Damage | 2 | | Order | 1 | | Control | 3 | | Spirit | 2 | | Summon | 3 | | Chaos | 4 | | Ward | 2 | | Void | 3 | | Counter | 3 | | | | A spell can have multiple aspects and types but only one base. Combining multiple types or aspects requires that the base always be Chaos. You may add up to 3 additional axes in total. Each additional axis has a cost and the cost is cumulative: | Additional Axis | Axis Cost | | --------------- | --------- | | 1st | 1 | | 2nd | 2 | | 3rd | 5 |","description":"","headingLevel":3,"fileSlug":"spell-creation"},{"title":"Power Modifier (PM)","pageTitle":"Creating a Spell","breadcrumb":"Creating a Spell › Procedure › Power Modifier (PM)","url":"/guides/spell-creation/#power-modifier-pm","content":"| Effect Scope | PM | | -------------------------------------------------------- | --- | | Minor / localized (touch, single object) | 0 | | Small area / short range (room, few meters) | 1 | | Medium distance / wider effect (street, hill) | 2 | | Large distance / major area (town, city) | 3 | | Extreme distance / affects region, realm, or dimension | 4 | | World-altering / nearly impossible (other plane, planet) | 5 |","description":"","headingLevel":3,"fileSlug":"spell-creation"},{"title":"Procedure","pageTitle":"Creating a Spell","breadcrumb":"Creating a Spell › Procedure","url":"/guides/spell-creation/#procedure","content":"Write the spell sentence (name, descriptor, base, effect). Choose Base (Order, Spirit, Chaos, or Void) and note its point value. Choose at least one Aspect and one Type. If you use multiple aspects or types, the base must be Chaos and additional axis costs apply. Sum points: Base + Aspect(s) + Type(s) + additional axis cost. You may not have more than 3 Aspects or 3 Types total. And you many not have more than 5 combined axis (aspect or type) Map the total points to Spell Level using the Level Mapping table. Apply Power Modifier (PM) from effect scope (touch up to world-altering). Final spell level = base level + PM.","description":"","headingLevel":2,"fileSlug":"spell-creation"},{"title":"Spell Sentence","pageTitle":"Creating a Spell","breadcrumb":"Creating a Spell › Procedure › Spell Sentence","url":"/guides/spell-creation/#spell-sentence","content":"!magic Spell Name is a \\descriptor\\ \\base\\ spell that \\does something\\.","description":"","headingLevel":3,"fileSlug":"spell-creation"},{"title":"Type Creation","pageTitle":"Type Creation","breadcrumb":"Type Creation","url":"/guides/type/","content":"Types are an umbrella tag. They are a specific sentence, and often have a parent type from which they hail. The parent type does not have a parent type — no grandparents here.","description":"","headingLevel":1,"fileSlug":"type"},{"title":"Procedure","pageTitle":"Type Creation","breadcrumb":"Type Creation › Procedure","url":"/guides/type/#procedure","content":"Create a type sentence (descriptor, type name, specialization). Assign a weakness (required). Determine magic access: Can Use Magic vs Can Learn Magic (or none). If the setting uses spellcasting, optionally set Base MAI and allowed Aspects or casting means (e.g. runes, tech, verbal). Define at least 2 abilities tied to the type. For each ability beyond 2, add another weakness or flaw.","description":"","headingLevel":2,"fileSlug":"type"},{"title":"Type Sentence","pageTitle":"Type Creation","breadcrumb":"Type Creation › Procedure › Type Sentence","url":"/guides/type/#type-sentence","content":"!character Type This type is a \\descriptor\\ \\type\\ who \\specializes in\\. Types are what most other TTRPGs call classes or archetypes. The descriptor defines the type's flavor or approach. The type is the role or category (e.g. warrior, spell-wright). The specialization describes what the type does or is known for — the defining action or focus. In settings where only species considered human exist (e.g. Earth), Base MAI for spellcasting may be set by type instead of species. If both species and type have a Base MAI, use the higher of the two (do not add them together). Specializes In should always start with a verb and should never start with 'specializes in'. Examples Champion — This type is a \\disciplined \\warrior who \\anchors the physical world against magic. Weakness: Kinetic Friction Magic: None Abilities: - Use Combat Training to hold the line and protect allies. - Call upon Discipline to resist magical influence and push through hardship. Spell-wright — This type is a \\meta-phys","description":"","headingLevel":3,"fileSlug":"type"},{"title":"Tag & Tally","pageTitle":"Tag & Tally","breadcrumb":"Tag & Tally","url":"/index/","content":"Tag & Tally is a narrative-first tabletop RPG where every thing is defined by two things &mdash; a sentence and a level. The sentence tells you what it is; The number tells you how tough they are. Tag &amp; Tall is designed for solo first, but cooperative or GM-led stories work perfectly well. The system runs on tags that shape your actions and tallies that track momentum, wounds, and stakes. You won’t need pages of stats. Just a line that speaks your truth. What's your line?","description":"","headingLevel":1,"fileSlug":"index"},{"title":"Authority and Responsibility","pageTitle":"Tag & Tally","breadcrumb":"Tag & Tally › Authority and Responsibility","url":"/index/#authority-and-responsibility","content":"Authority in play is shared, but clearly scoped. Players are responsible for: Declaring intent Choosing actions Applying tags they can meaningfully justify The system is responsible for: Determining difficulty Resolving uncertainty Producing outcomes and consequences The fiction must always reflect the results of mechanical resolution. Once dice are rolled and outcomes determined, the narrative adapts to those results rather than revising them. In solo play, the player fulfills both roles by following the procedures as written and allowing the system’s outcomes to stand, even when inconvenient. However, keep in mind if you don't like the direction of the game you are free to change it. It's your game. Play how you want.","description":"","headingLevel":2,"fileSlug":"index"},{"title":"Failure, Complication, and Forward Motion","pageTitle":"Tag & Tally","breadcrumb":"Tag & Tally › Failure, Complication, and Forward Motion","url":"/index/#failure-complication-and-forward-motion","content":"Failure does not halt progress. When a roll fails or partially succeeds, the scene must still change in a meaningful way. This change may take many forms: A quest advances in an unexpected direction An insight becomes corrupted, incomplete, or dangerous New pressure is introduced The character is altered rather than the situation Failure should never invalidate intent retroactively. The character tried, acted, and paid a cost. That cost becomes part of the ongoing fiction. If a failure would only delay play without introducing change, the scene should not be resolved mechanically.","description":"","headingLevel":2,"fileSlug":"index"},{"title":"Inaction, Delay, and Refusal","pageTitle":"Tag & Tally","breadcrumb":"Tag & Tally › Inaction, Delay, and Refusal","url":"/index/#inaction-delay-and-refusal","content":"Choosing not to act is still a choice. If a character avoids risk, withdraws from a situation, or refuses to pursue an intent, active quests continue to advance without them. Pressure escalates offscreen, stakes worsen, and opportunities may close. Inaction may preserve safety in the short term, but it does not preserve control. Scenes should only be resolved mechanically when characters engage with uncertainty. Avoidance resolves itself through narrative consequence rather than dice.","description":"","headingLevel":2,"fileSlug":"index"},{"title":"Reading the System Correctly","pageTitle":"Tag & Tally","breadcrumb":"Tag & Tally › Reading the System Correctly","url":"/index/#reading-the-system-correctly","content":"This game rewards: Clear intent Meaningful risk Accepting consequences This game resists: Grinding Repeated retries without change Optimization detached from fiction If you ever feel unsure which rule to apply, return to the core question: What will change if this action is resolved? If the answer is “nothing,” do not roll.","description":"","headingLevel":2,"fileSlug":"index"},{"title":"What This Game Is About","pageTitle":"Tag & Tally","breadcrumb":"Tag & Tally › What This Game Is About","url":"/index/#what-this-game-is-about","content":"This game is about pursuing quests that create change. Play centers on characters acting with intent in uncertain situations. Every meaningful action risks consequences that alter the character, the world, or both. Progress is not measured by accumulation or optimization, but by transformation: new knowledge, altered beliefs, broken alliances, and hard-earned advantages. The rules exist to apply pressure, force decisions, and ensure that outcomes matter. Success is rarely clean, failure is rarely final, and avoiding risk does not halt the world’s momentum. If nothing would change as a result of an action, the game does not ask you to roll.","description":"","headingLevel":2,"fileSlug":"index"},{"title":"Legal","pageTitle":"Legal","breadcrumb":"Legal","url":"/legal/","content":"Tag and Tally © 2025-2026 is licensed under CC BY-SA 4.0. To view a copy of this license, visit https://creativecommons.org/licenses/by-sa/4.0/ [terms-of-service|Terms of Service] | [privacy-policy|Privacy Policy]","description":"","headingLevel":1,"fileSlug":"legal"},{"title":"3rd Party Licenses","pageTitle":"Legal","breadcrumb":"Legal › 3rd Party Licenses","url":"/legal/#3rd-party-licenses","content":"This work includes material from the System Reference Document 5.2.1 (“SRD 5.2.1”) by Wizards of the Coast LLC, available at https://www.dndbeyond.com/srd. The SRD 5.2.1 is licensed under the Creative Commons Attribution 4.0 International License, available at https://creativecommons.org/licenses/by/4.0/. 5e Creature List 5e Species List 5e Classes List 5e Spells List","description":"","headingLevel":2,"fileSlug":"legal"},{"title":"Game Loop","pageTitle":"Game Loop","breadcrumb":"Game Loop","url":"/mechanics/core/game-loop/","content":"The player makes all the rolls. A scene is resolved when its declared intent is achieved, thwarted, or meaningfully altered. If multiple actions are required, resolve them in sequence, escalating consequences after each roll. The Scene Level sets the base difficulty for all actions in the scene unless the task, item, character has an already defined level. This level replaces the scene level for the task applied to this target only. New scene or environmental tags may be introduced only as a consequence of a roll or a change in the fiction. Escalation should meaningfully alter the intent, stakes, or available actions after each roll. Escalation occurs after any roll that does not fully resolve the declared intent. A scene may be closed early if its stakes are no longer relevant or its intent is rendered impossible. If neither intent nor stakes would change as a result of a roll, do not resolve the scene mechanically. A scene may close unresolved, carrying its stakes forward as complica","description":"","headingLevel":1,"fileSlug":"game-loop"},{"title":"Procedure","pageTitle":"Game Loop","breadcrumb":"Game Loop › Procedure","url":"/mechanics/core/game-loop/#procedure","content":"Roll a Scene Level - Get a Scene Level 1d4+2 is the default roll but you could use the hex method for increasing difficulty possibility based on the last scene | Last Scene Level | Dice Formula | Level Range | | ---------------- | ------------ | ----------- | | Starting scene | 1d4+2 | 3-6 | | 3-4 | 1d6+2 | 3-8 | | 5-6 | 1d8+2 | 3-10 | | 7-10 | 1d10+2 | 3-10\\ | \\ 11 & 12 in this Range are a 10 (optional) Roll a Scene Sentence Roll/Create additional Scene modifiers: weather, time of day, season, phase of the moon, etc Declare Intent - What is the characters immediate goal for this scene? - What quests is advanced or threatened? Establish Stakes - If successful, what is gained - If failed, what is lost or complicated Resolve the Scene - Choose the action(s) taken to pursue the declared intent. The number of actions is determined by the fiction and the established stakes. - Standard Task: Resolve with a single roll vs DC. - High-Stakes Conflict: Resolve using the 5-Phase Sequence in the C","description":"","headingLevel":2,"fileSlug":"game-loop"},{"title":"Game Sentences","pageTitle":"Game Sentences","breadcrumb":"Game Sentences","url":"/mechanics/core/game-sentences/","content":"Everything in the game can be defined with a singular sentence at its core. But most things also have additional tags that can ease or hinder abilities, skills and offer a greater variety to even the simplest of sentences. !scene Scene This scene is a \\descriptor\\ \\scene type\\ that \\does something\\ !character Character Name is a \\descriptor\\ \\species\\ \\type\\ who \\specializes in\\ !character NPC Name is a \\descriptor \\species \\type who \\does something special. They are motivated \\a motivation and have a goal \\a goal. In combat, they deal \\damage type damage with \\attack of choice, but they \\have a secret. !character Species This species is a \\aged \\descriptor\\ people who \\cultural trait or motivation\\ and \\physical/biological feature\\. !character Type This type is a \\descriptor\\ \\type\\ who \\specializes in\\ !wounds Wounds This wound is a \\descriptor \\type of mark located on \\the body part that \\specific mechanical detriment. !creature Creature Name (\\disposition \\descriptor \\type):This cr","description":"","headingLevel":1,"fileSlug":"game-sentences"},{"title":"Resolution","pageTitle":"Resolution","breadcrumb":"Resolution","url":"/mechanics/core/resolution/","content":"","description":"","headingLevel":1,"fileSlug":"resolution"},{"title":"Basic Resolution","pageTitle":"Resolution","breadcrumb":"Resolution › Basic Resolution","url":"/mechanics/core/resolution/#basic-resolution","content":"Tags & Tally has a fail forward resolution mechanic. Everything in the game has a level between 1 and 10. A conflict, interaction, or task that has the possibility of changing the story should roll against a target DC. The DC of anything in the game is three times its level. DC = 3 \\* level The player always rolls 1d20 against this DC and uses the table below to determine the outcome. The Level may be modified by tags, easing or hindering the level of the task to be used as the target DC. | d20 | Result | Details | | ------------ | ------------ | ------------------------------------ | | 1 | Fail, and | Fail, and things are worse | | 2 to DC-6 | Fail, but | Fail, but something else helps you | | DC-5 to DC-1 | Success, but | Success, but not exactly as expected | | DC to DC+4 | Success | Exactly as you expected | | DC+5 + | Success, and | Success, and things are better |","description":"","headingLevel":2,"fileSlug":"resolution"},{"title":"Cheat Sheet","pageTitle":"Resolution","breadcrumb":"Resolution › Cheat Sheet","url":"/mechanics/core/resolution/#cheat-sheet","content":"| Level | 1 | 2 | 3 | 4 | 5 | | ------------- | ----- | ----- | ----- | ------ | ------ | | DC | 3 | 6 | 9 | 12 | 15 | | Fail, and | 1 | 1 | 1 | 1 | 1 | | Fail, but | 2 | 2 | 2-3 | 2-7 | 2-9 | | Success, but | — | 3-5 | 4-8 | 8-11 | 10-14 | | Success | 3-7 | 6-10 | 9-13 | 12-16 | 15-19 | | Success, and | 8+ | 11+ | 14+ | 17+ | 20 | | Threshold | 2 | 2 | 2 | 3 | 3 | | Level | 6 | 7 | 8 | 9 | 10 | | ------------- | ------ | ------ | ------ | ------ | ------ | | DC | 18 | 21 | 24 | 27 | 30 | | Fail, and | 1 | 1 | 1 | 1 | 1 | | Fail, but | 2-14 | 2-15 | 2-18 | 2-20 | 2-20 | | Success, but | 15-17 | 16-20 | 19-20 | — | — | | Success | 18-20 | — | — | — | — | | Success, and | — | — | — | — | — | | Threshold | 3 | 4 | 4 | 5 | 5 |","description":"","headingLevel":2,"fileSlug":"resolution"},{"title":"Levels of Difficulty","pageTitle":"Resolution","breadcrumb":"Resolution › Levels of Difficulty","url":"/mechanics/core/resolution/#levels-of-difficulty","content":"| Level | DC | Description | | ----- | --- | ------------ | | 1 | 3 | Simple | | 2 | 6 | Standard | | 3 | 9 | Demanding | | 4 | 12 | Difficult | | 5 | 15 | Challenging | | 6 | 18 | Intimidating | | 7 | 21 | Formidable | | 8 | 24 | Heroic | | 9 | 27 | Immortal | | 10 | 30 | Impossible |","description":"","headingLevel":2,"fileSlug":"resolution"},{"title":"Modifying the Difficulty","pageTitle":"Resolution","breadcrumb":"Resolution › Modifying the Difficulty","url":"/mechanics/core/resolution/#modifying-the-difficulty","content":"The situation and your character tags can modify the target difficulty. This is done by either easing the difficulty or hindering the difficulty. Easing: Easing the difficulty means that you lower the level of the task being preformed. Hindering: Hindering the difficulty means that you raise the level of the task being preformed. Remember that the target number (DC) to hit is 3 times the level, so the target number is essentially lowered or raised by as many three times as many as the task is eased or hindered.","description":"","headingLevel":2,"fileSlug":"resolution"},{"title":"Player vs Player Resolution","pageTitle":"Resolution","breadcrumb":"Resolution › Basic Resolution › Player vs Player Resolution","url":"/mechanics/core/resolution/#player-vs-player-resolution","content":"When a contested roll against two players characters happens both a d20 and add +1 (or the Tiered modifier) for any tag that eases the roll, add -1 (or the Tiered modifier) for any tag that hinders the roll. The player who initiates the conflict is Player A and the other is Player B, using Player A's Total - Player B's Total use the following Resolution table to determine the outcome of the conflict. | (Player A total - Player B total) | Outcome for Player A | | --------------------------------- | ----------------------- | | ≤ -5 | Fail, and | | -4 to -1 | Fail, but | | 0 | Success, but (tie case) | | 1 to 4 | Success | | ≥ 5 | Success, and |","description":"","headingLevel":3,"fileSlug":"resolution"},{"title":"Tags","pageTitle":"Tags","breadcrumb":"Tags","url":"/mechanics/core/tags/","content":"Tags are the basis of all descriptive sentences in Tag & Tally. Tags should always ease or hinder one or more actions. Tags should expand what the character can attempt, not repeat something they already do. When designing your characters, items, creatures, etc. you should start with the umbrella tags and work your way out so that you don't overlap tags that come with types, species, specialties etc.","description":"","headingLevel":1,"fileSlug":"tags"},{"title":"How to Use a Tag","pageTitle":"Tags","breadcrumb":"Tags › How to Use a Tag","url":"/mechanics/core/tags/#how-to-use-a-tag","content":"Tags can be used with justification to ease any task. But there is a limit to how many tags you can apply to any given task. This is know as the Task Threshold. Principle: If a tag meaningfully contributes to the action, it should be applied; the Task Threshold governs how many can be counted mechanically. Each source counts as 1, regardless of how much it eases. You may use a maximum of 2 gear or physical assets to ease tasks. A source's tier determines how many steps it eases by. You must justify each source as relevant to the task at hand. - All tags that apply should be applied. Use the information below as a guideline on how to determine what should be applied: - Relevance: Does this tag directly interact with or enable the action? - Specificity: Does this tag give a distinct detail or context about the action? - Contextual: Could using this tag misrepresent the fiction? An umbrella tag may not be applied simultaneously with any of its specific sub-tags if both would affect the sa","description":"","headingLevel":2,"fileSlug":"tags"},{"title":"Tag Categories","pageTitle":"Tags","breadcrumb":"Tags › Tag Categories","url":"/mechanics/core/tags/#tag-categories","content":"There are several categories of tags. A static tag is a tag that cannot gain tiers through use. These are tags that are fact, they don't change with practice. An umbrella tag represents a group of other tags, skills, traits and properties that anyone with the tag possess. A tag that is part of a sentence is an umbrella tag. Umbrella tags cannot gain tiers. But the tags that are underneath the Umbrella (not in the sentence), can gain tiers per use. More on Tiered Tags later. Every Umbrella tag is a sentence and each umbrella sentence 3 sub-tags — 1 flaw and 2 other tags. A temporary tag is active until it is removed. Temporary tags can be removed by actions in game. Most temporary tags wear off. At the start of any new scene, or major change in scene status, a player may roll any die. If the roll is even the tag is cleared, if the roll is odd the tag remains active for the duration of the scene. The next scene the player may roll again. A permanent tag is a tag that cannot be removed fr","description":"","headingLevel":2,"fileSlug":"tags"},{"title":"Tag Notation","pageTitle":"Tags","breadcrumb":"Tags › Tag Notation","url":"/mechanics/core/tags/#tag-notation","content":"Tags have a specific notation \\Tag information N# (X) !:- Where N represents the status of the tag, S for Static, or T for Tiered \\# represents the tier of the tag (1-4). If a tier is 1 you can omit both the T and the value. X represents the number of tallies a Tag has earned towards the next tier. If its has 0 you can omit both the parenthesis and the number. ! represents the fact that a tag has been mastered, you can remove the (5) when the tier 4 master has been reached : represents the fact that a tag is temporary. \\- represets the fact that the tag goes in the reverse direction","description":"","headingLevel":2,"fileSlug":"tags"},{"title":"Tag Types","pageTitle":"Tags","breadcrumb":"Tags › Tag Types","url":"/mechanics/core/tags/#tag-types","content":"There are several types of Tags. A scene tag represent temporary conditions, environmental factors, or narrative elements that affect all participants within a scene. Scene tags are always applied if applicable and do not count against the number of tags used to ease a player's tasks (even if it is easing the task). Scene tags expire at the end of the scene unless continued forward specifically when the scene changes. A background tag represents something that changed the item in the past that has an effect on how the attached item preforms tasks, interact with others, etc. Background tags cannot gain tiers, they are static. A trait tag represents a trait, or feature of the attached item's personality or physicality that has an effect on how the attached item preforms tasks, interact with others, etc. Trait tags cannot gain tiers, they are static. A skill tag or an ability tag represents something the attached item can do that has an effect on how the attached item preforms tasks, inte","description":"","headingLevel":2,"fileSlug":"tags"},{"title":"Tier Advancement and Mastery","pageTitle":"Tags","breadcrumb":"Tags › Tiered Tags › Tier Advancement and Mastery","url":"/mechanics/core/tags/#tier-advancement-and-mastery","content":"Tags are advanced by using them. When a player uses a tag to ease (or hinder) an action and they roll either a 1 or a 20 (regardless of the success of the roll), the tags used in this action gain 1 Tally. Each Tier requires 5 Tallies before it can advance to the next Tier. When a Tier 4 tag hits that 5th Tally the Tag is considered Mastered. And can remove the Tally marks and denote the mastery of the tag. See the Notations section.","description":"","headingLevel":3,"fileSlug":"tags"},{"title":"Tiered Tags","pageTitle":"Tags","breadcrumb":"Tags › Tiered Tags","url":"/mechanics/core/tags/#tiered-tags","content":"All tags, except umbrella (those in a sentence) and static tags, can increase in Tier. All Tags start at Tier 1 and do not require notation. Tags with a tier are one source, but they ease by the tier level. There are 4 Tiers. | Level | Tier | | ----- | ------- | | 1 | Novice | | 2 | Skilled | | 3 | Expert | | 4 | Master |","description":"","headingLevel":2,"fileSlug":"tags"},{"title":"Using Tags: Intent vs Justification","pageTitle":"Tags","breadcrumb":"Tags › How to Use a Tag › Using Tags: Intent vs Justification","url":"/mechanics/core/tags/#using-tags-intent-vs-justification","content":"Tags represent facts about the character, the situation, or the world. A tag may be applied to a task only if it meaningfully alters how the action is performed or what risks are involved. Tags that merely restate the declared intent or describe the desired outcome do not apply. When in doubt: If the tag would still matter even if the action failed, it applies. If the tag only matters when the action succeeds, it does not. The goal of tags is not to maximize bonuses, but to reflect the fiction accurately.","description":"","headingLevel":3,"fileSlug":"tags"},{"title":"Combat","pageTitle":"Combat","breadcrumb":"Combat","url":"/mechanics/foundational/combat/","content":"In Tag and Tally, there is a 5 stage combat loop. Each stage is one roll by the player that does something very specific. The Opening — who has advantage Tactical Maneuver — set up the stage for your \"attack\" The Attack — you attempt your plan The Counter — your opponent gets a turn (you roll defense) The Resolution — how it all ended","description":"","headingLevel":1,"fileSlug":"combat"},{"title":"Armor","pageTitle":"Combat","breadcrumb":"Combat › Armor","url":"/mechanics/foundational/combat/#armor","content":"Armor eases defense and hinders stealth and decreases carrying capacity by 1. | Armor | Ease Defense | Hinder Stealth | Carrying Capacity Reduced | | ------ | ------------ | -------------- | ------------------------- | | Light | 1 step | 0 steps | 0 | | Medium | 2 steps | 1 step | 0 | | Heavy | 3 steps | 2 steps | 1 |","description":"","headingLevel":2,"fileSlug":"combat"},{"title":"Phase 1 — The Opening","pageTitle":"Combat","breadcrumb":"Combat › Armor › Phase 1 — The Opening","url":"/mechanics/foundational/combat/#phase-1-the-opening","content":"Players roll against the DC of the target scene/creature/task. | Attack d20 | Result | Outcome | | ---------- | ------------ | ----------------------------------------- | | 1 | Fail, and | Hindered by 2 | | 2 to DC-6 | Fail, but | Hindered by 1, but the enemy is surprised | | DC-5 to -1 | Success, but | Ease by 1, but take a strain | | DC to DC+4 | Success | Ease by 1 | | DC+5+ | Success, and | Ease by 2 | The outcome affects only your Tactical Maneuver","description":"","headingLevel":3,"fileSlug":"combat"},{"title":"Phase 2 — Tactical Maneuver","pageTitle":"Combat","breadcrumb":"Combat › Armor › Phase 2 — Tactical Maneuver","url":"/mechanics/foundational/combat/#phase-2-tactical-maneuver","content":"The Players try to ease their own actions, or hinder their opponents actions. This is an action taken against the scene ie: putting out the lights, throwing out caltrops, casting a fog spell to create a scene tag that applies to everyone or by easing their own actions ie: drinking a potion, casting a buffing spell, hiding in the shadows. | Attack d20 | Result | Outcome | | ---------- | ------------ | --------------------------------------------------------- | | 1 | Fail, and | Your actions failed, and you are hindered by 1 | | 2 to DC-6 | Fail, but | Your actions failed, but nothing bad happens | | DC-5 to -1 | Success, but | Your actions succeeded, but you are hindered by 1 | | DC to DC+4 | Success | Your actions succeed and the tags are applied universally | | DC+5+ | Success, and | Your actions succeed and your next actions are eased by 1 | The outcome come affects your Attack and Counter Rolls","description":"","headingLevel":3,"fileSlug":"combat"},{"title":"Phase 3 — The Attack","pageTitle":"Combat","breadcrumb":"Combat › Armor › Phase 3 — The Attack","url":"/mechanics/foundational/combat/#phase-3-the-attack","content":"The Players go all out and try to accomplish their goal applying the scene tags as necessary and any additional ones that apply. | Attack d20 | Result | Narrative | Outcome | | ---------- | ------------ | ------------------------- | -------------- | | 1 | Fail, and | Disaster strikes. | Hinder 2 steps | | 2 to DC-6 | Fail, but | Missed, but kept guard. | No Modifier | | DC-5 to -1 | Success, but | Hit, but left an opening. | Hinder 1 step | | DC to DC+4 | Success | Clean strike. | Ease 1 step | | DC+5+ | Success, and | Devastating blow. | Ease 2 steps | The outcome affects the Resolution.","description":"","headingLevel":3,"fileSlug":"combat"},{"title":"Phase 4 — The Counter","pageTitle":"Combat","breadcrumb":"Combat › Armor › Phase 4 — The Counter","url":"/mechanics/foundational/combat/#phase-4-the-counter","content":"The creatures get a turn to counter. The scene tags still apply and the players can use their tags ease/hinder as they apply. The player rolls a defense roll. | Attack d20 | Result | Narrative | Outcome | | ---------- | ------------ | --------------------------------------------- | -------------- | | 1 | Fail, and | Caught off guard, defenses shattered. | Hinder 2 steps | | 2 to DC-6 | Fail, but | Forced to retreat, but kept your shield up. | No Modifier | | DC-5 to -1 | Success, but | Blocked the blow, but the impact was jarring. | Hinder 1 step | | DC to DC+4 | Success | Perfect parry or dodge. | Ease 1 step | | DC+5+ | Success, and | Counter-parry creates a massive opening. | Ease 2 steps | The outcome affects the resolution.","description":"","headingLevel":3,"fileSlug":"combat"},{"title":"Phase 5 — The Resolution","pageTitle":"Combat","breadcrumb":"Combat › Armor › Phase 5 — The Resolution","url":"/mechanics/foundational/combat/#phase-5-the-resolution","content":"The dust has settled. This is what happened. | Final d20 | Outcome | Narrative Result | The Wound | | ---------- | ------------ | -------------------- | ------------------- | | 1 | Fail, and | Crushing Defeat. | Lasting Scar | | 2 to DC-6 | Fail, but | Driven back/Escaped. | Debilitating Injury | | DC-5 to -1 | Success, but | Messy Victory. | Lingering Trauma | | DC to DC+4 | Success | Clear Victory. | Strain | | DC+5+ | Success, and | Flawless dominance. | Unscathed | A success or better means the objective of the conflict (killing the monster, escaping the guards, clearing the room) is achieved. A failure means the objective was lost, or achieved at a terrible narrative cost alongside the injury.","description":"","headingLevel":3,"fileSlug":"combat"},{"title":"Gear","pageTitle":"Gear","breadcrumb":"Gear","url":"/mechanics/foundational/gear/","content":"There are three types of gear. Functional, Extraordinary and Ephemeral Gear. Functional gear is considered things that are strictly necessary to preform some part of your type or specialty. You can't be a photographer without a camera. You can't be a Scavenger without tools of some sort or another. If these tools only provide the how you do something you can carry them outside your 10 slot loadout. (They would still take up space in your bagged or zoned system if you chose to use either one.) If a gear eases a task, or has special properties, then it becomes Extraordinary Gear or Ephemeral Gear. Extraordinary Gear takes up a slot in your 10 slot load out. Ephemeral Gear is things like magical tattoos, brands, cybernetics, and apps. Containers can only store so much and have a physical limit. This limit is dictated by the items level. Since Characters do not have a level, the cap is 5 ephemeral gear items on the body — tattoos, brands, cybernetics, or anything that physically alters the","description":"","headingLevel":1,"fileSlug":"gear"},{"title":"Armor","pageTitle":"Gear","breadcrumb":"Gear › Armor","url":"/mechanics/foundational/gear/#armor","content":"There are three different armor types. Armor eases defense and hinders stealth and can decreases carrying capacity. | Armor | Ease Defense | Hinder Stealth | Carrying Capacity Reduced | | ------ | ------------ | -------------- | ------------------------- | | Light | 1 step | 0 steps | 0 | | Medium | 2 steps | 1 step | 0 | | Heavy | 3 steps | 2 steps | 1 |","description":"","headingLevel":2,"fileSlug":"gear"},{"title":"Consumables","pageTitle":"Gear","breadcrumb":"Gear › Consumables","url":"/mechanics/foundational/gear/#consumables","content":"Consumables are pieces of gear that have a limited lifetime. Such as rations, potions, scrolls. Each consumable must dictate how it is depleted. There are two options -- \\single-use and \\depletion. Some consumables leave behind remnants that can be used later. These things such as paint, chalk have a durability that determines if the remnant is reusable again. One use — \\single-use Multiple uses: Roll a 1 on a d20 - \\depletion - Level 1-4 roll at disadvantage - Level 5-7 roll normally - Level 8-10 roll at advantage A Remnant is the physical trace left in the environment after a consumable is used (e.g., chalk marks on a wall, paint on a door, or a chemical trail on the ground). These items that leave behind marks should have a \\remnant tag and are required to add a durability tag for the remnant. The Remnant's Durability determines if the mark remains readable or functional over time. When the environment or time puts the mark at risk (rain, traffic, fading), roll a d20. On a 1, the Re","description":"","headingLevel":2,"fileSlug":"gear"},{"title":"Containers","pageTitle":"Gear","breadcrumb":"Gear › Containers","url":"/mechanics/foundational/gear/#containers","content":"Containers can contain things. A smartphone can contain apps. A keyring can contain keys or keychain dongles and tools. A kit is essentially a container. A bag or backpack is also a container. There are two types of containers the ephemeral/narrative container which is used purely for narrative organizational purposes, and space constraining containers that are used in the bagged inventory systems. Containers can contain up to their level of things plus two for small items like key chains, charms on a necklace/bracelet, a belt or belt pouch. Most containers can contain their level 2 medium items. Large bags for resource intense came contain level + 2 large items. | Container | Contains | | --------- | ---------------------- | | Small | Level + 2 small items | | Most | Level 2 medium items | | Resource | Level + 2 resources | | Item Size | Small | Medium | Large | Definition | | --------- | ----- | ------ | ----- | ------------------------------------------------------------------------","description":"","headingLevel":2,"fileSlug":"gear"},{"title":"Extraordinary Gear","pageTitle":"Gear","breadcrumb":"Gear › Extraordinary Gear","url":"/mechanics/foundational/gear/#extraordinary-gear","content":"All extraordinary gear has some sort of level. The level determines many things about the item depending on what it is. But the level on all gear tells you about it's quaility. | Level | Quality | Description | | :---- | :--------------- | :----------------------------------------------------------------------------------------------------------- | | 1 | Junk / Makeshift | Barely functional. Held together by tape, luck, or weak magic. Likely to glitch or fail under pressure. | | 2 | Budget / Surplus | Mass-produced or outdated surplus. Reliable for daily use, but lacks specialized features or refinement. | | 3 | Standard | The \"Consumer Grade\" baseline. Reliable, middle-of-the-road gear used by the general populace. | | 4 | Professional | Specialized gear used by experts. Hardened against wear and tear; refined materials and consistent output. | | 5 | Superior | High-end \"Flagship\" models. Exceptional craftsmanship that stands out to those in the trade. | | 6 | Elite / Tactical | Cutti","description":"","headingLevel":2,"fileSlug":"gear"},{"title":"Kits","pageTitle":"Gear","breadcrumb":"Gear › Kits","url":"/mechanics/foundational/gear/#kits","content":"Crafting, Thieving, Hunting, Trapping, Navigation, and other specialty tasks that have multiple tools can have a kit that contain all the tools necessary and only take up one slot. Kits contain generic tools at their level — a hammer, a needle and thread, fishing line, a skinning knife. But you can add up to their level times 2 of a specialized item related to that kit — special ink to a ritual kit, a healing potion for a medical kit, a level 3 hunting rifle to a hunting kit Items that can be consumed like bandages, potions, salves, inks, chalk, paint, etc. follow the consumable rules.","description":"","headingLevel":2,"fileSlug":"gear"},{"title":"Smartphones/Laptops","pageTitle":"Gear","breadcrumb":"Gear › Smartphones/Laptops","url":"/mechanics/foundational/gear/#smartphoneslaptops","content":"In a modern setting Smartphones and Laptops are run of the mill nearly everyone has one device. They provide basic computation and socialization apps. The following apps are always available: GPS/Map, Phone, Camera, Internet, Notes, Music. A device may contain its level times 3 specialized apps. Things like Social Networking Platforms, Drawing, Anything you would need to download from an app store or magical app if your world provides such mechanics.","description":"","headingLevel":2,"fileSlug":"gear"},{"title":"Weapons","pageTitle":"Gear","breadcrumb":"Gear › Weapons","url":"/mechanics/foundational/gear/#weapons","content":"Weapons come in different damage types. Creature attacks also do these same damage types. | d8 | Damage Types | | --- | ----------------------------------------------- | | 1 | Physical (piercing, slashing, crushing weapons) | | 2 | Psychic (mental, psychic) | | 3 | Elemental (fire, air, earth, water) | | 4 | Necrotic (death, undead, spirits, blood magic) | | 5 | Radiant (divine, angelic, light) | | 6 | Shadow (shadows, Nether magic) | | 7 | Chaos (Faerie Magic) | | 8 | Toxic (poisons, venom, disease, radiation) |","description":"","headingLevel":2,"fileSlug":"gear"},{"title":"Insights","pageTitle":"Insights","breadcrumb":"Insights","url":"/mechanics/foundational/insights/","content":"Insights are discoveries that your character makes that advance stories. !insight Insight This insight reveals information about a \\Status\\ \\Subject\\ regarding its \\Modifier\\. Status is an indicator of whether or not the subject is new or existing. You get to choose and create which one it is based on your play-through. There are 4 different subjects an insight can provide information about: Factions, NPCs, Creatures, and Quests. Each subject has specific insight categories that help determine exactly what was revealed to the character. Strength insights reveal the creature's strength to the character. Weakness insights reveal the creature's weakness to the character. Secret insights reveal a faction or NPC's secret to the character. Location insights are tallied insights that fill 5 marks on the tally before finding the location. Goal insights are tallied insights that fill 5 marks on the tally before finishing. Plan insights are tallied insights that fill 5 marks on the tally before ","description":"","headingLevel":1,"fileSlug":"insights"},{"title":"Insight Modifier Creature","pageTitle":"Insights","breadcrumb":"Insights › Insight Modifier Creature","url":"/mechanics/foundational/insights/#insight-modifier-creature","content":"| 1d4 | Value | | --- | -------- | | 1 | Motive | | 2 | Strength | | 3 | Weakness | | 4 | Location |","description":"","headingLevel":2,"fileSlug":"insights"},{"title":"Insight Modifier Faction","pageTitle":"Insights","breadcrumb":"Insights › Insight Modifier Faction","url":"/mechanics/foundational/insights/#insight-modifier-faction","content":"| 1d6 | Value | | --- | -------- | | 1-2 | Secret | | 3-4 | Goal | | 5-6 | Location |","description":"","headingLevel":2,"fileSlug":"insights"},{"title":"Insight Modifier NPC","pageTitle":"Insights","breadcrumb":"Insights › Insight Modifier NPC","url":"/mechanics/foundational/insights/#insight-modifier-npc","content":"| 1d6 | Value | | --- | -------- | | 1-2 | Secret | | 3-4 | Goal | | 5-6 | Location |","description":"","headingLevel":2,"fileSlug":"insights"},{"title":"Insight Modifier Quest","pageTitle":"Insights","breadcrumb":"Insights › Insight Modifier Quest","url":"/mechanics/foundational/insights/#insight-modifier-quest","content":"| 1d6 | Value | | --- | --------- | | 1-3 | Plan | | 4-5 | Location | | 6 | Countdown |","description":"","headingLevel":2,"fileSlug":"insights"},{"title":"Inventory","pageTitle":"Inventory","breadcrumb":"Inventory","url":"/mechanics/foundational/inventory/","content":"Inventory is a management system. Your homebase can have unlimited storage, but what you take with you is limited. There are two models. You can pick for your game. Modern games typically lean towards the Zone model. Fantasy can use both, but tends towards a more bag style system. But feel free to mix and match for your game. We also present you with a hybrid solution. The Combat Rule Using any item takes 1 Action. Whether it is scanning with Ocular HUDs, drinking a potion from a pouch, or pulling a tool from a backpack, it consumes your action for the turn.","description":"","headingLevel":1,"fileSlug":"inventory"},{"title":"Bagged Inventory","pageTitle":"Inventory","breadcrumb":"Inventory › Bagged Inventory","url":"/mechanics/foundational/inventory/#bagged-inventory","content":"With bagged inventory you carry your gear in your bags, or your hands and armor on your body. If you don't have slots in your bags you can't bring it with you or pick it up unless you hold it. This does not mean you can't use them in one action, only that your slots are generic and that you can only hold so much of so many kinds of things. | Container | Contains | | ------------ | ---------------------- | | Belt Pouch | Level + 2 small items | | Backpack | Level * 2 medium items | | Resource Bag | Level + 2 resources | | Item Size | Small | Medium | Large | Definition | | --------- | ----- | ------ | ----- | ---------------------------------------------------------------------------------- | | Small | 1 | 2 | 4 | Small items are things like scrolls, keys, dice, potions | | Medium | — | 1 | 2 | Medium items are what most things are | | Large | — | — | 1 | Large items are either heavy or large, like a great sword or shield or plate armor | | Resource Type | Stack Size | Reasoning | | ---","description":"","headingLevel":2,"fileSlug":"inventory"},{"title":"Containers","pageTitle":"Inventory","breadcrumb":"Inventory › Containers","url":"/mechanics/foundational/inventory/#containers","content":"Containers can contain things. They can contain up to their level of things. But the container itself only take up one slot. A Bag of Holding, Portable Hole, or what I like to call a TARDIS container — \"bigger on the inside\" — has a 3 times their level max capacity and cannot contain other multi-dimensional containers.","description":"","headingLevel":2,"fileSlug":"inventory"},{"title":"Cybernetics","pageTitle":"Inventory","breadcrumb":"Inventory › Cybernetics","url":"/mechanics/foundational/inventory/#cybernetics","content":"Cybernetics like Tattoos are allowed in some worlds. They should not be used in combination with magical tattoos. In otherwords you cannot have a cybernetic and a magical tattoo in the same location. You can replace most items in your zones with cybernetics and cannot use that slot for anything else. The following slots are unavailable for cybernetics: Somatic Underlayer Courier Slot All Home Slots in Zone 5","description":"","headingLevel":2,"fileSlug":"inventory"},{"title":"Hybrid.","pageTitle":"Inventory","breadcrumb":"Inventory › Hybrid.","url":"/mechanics/foundational/inventory/#hybrid","content":"You can combine the best of both systems. You can use the following areas as places to carry bags of inventory outside of the container rules the Zone system follows. This is just an explicit location for incorporating the Bagged System. Zone 2 Back can carry a Backpack or Resourse bag Zone 3 Hips can carry belt pouches Zone 4 Courier Slot can carry a belt pouch, backpack or resource bag.","description":"","headingLevel":2,"fileSlug":"inventory"},{"title":"Kits","pageTitle":"Inventory","breadcrumb":"Inventory › Kits","url":"/mechanics/foundational/inventory/#kits","content":"Crafting, Theiving, Hunting, Trapping, Navigation, and other specialty tasks that have multiple tools can have a kit that contain all the tools necessary and only take up one slot.","description":"","headingLevel":2,"fileSlug":"inventory"},{"title":"Tattoos","pageTitle":"Inventory","breadcrumb":"Inventory › Tattoos","url":"/mechanics/foundational/inventory/#tattoos","content":"In some worlds tattoos can be magical and should be included with the inventory as items to be used. Tattoos are considering Somatic in Zone 1. Magical Tattoos can be found in the following zones of the body Sternum Over the Heart Shoulder (Left) Shoulder (Right) Arm Sleeve (Left) Arm Sleeve (Right) Thigh (Left) Thigh (Right) Calf (Left) Calf (Right) Back Shoulder Blade (Left) Shoulder Blade (Right) Neck You can only have one tattoo in each of these locations.","description":"","headingLevel":2,"fileSlug":"inventory"},{"title":"Zone System","pageTitle":"Inventory","breadcrumb":"Inventory › Zone System","url":"/mechanics/foundational/inventory/#zone-system","content":"In the Zone system your inventory goes in a very specific slot on your body and it must fit form factor. You can't put gloves on your feet, or a dagger on your eyes. Things must be appropriate for the slot. Some items may be containers and should follow the containers rule. Zone 1: The Senses (Head & Neck) These slots are for items that filter the world or provide constant data. Cranium (Head): Hats, helmets, or neural interfaces. Ocular (Eyes): Glasses, contacts, or HUD-enabled lenses. Auditory (Ears): Earbuds, comms pieces, or dampeners. Olfactory/Respiration (Face): Masks, filters, or specialized scents. Cervical (Neck): Scarves, necklaces, or protective collars. Oral (Mouth): Lozenges, gum, or voice modulators. Somatic (Mental/Soul): Non-physical \"slots\" like active digital apps or ongoing spells. Zone 2: The Core (Torso & Arms) This zone covers protection and utility that requires a \"reach.\" Outer Layer (Chest): Jackets, hoodies, or tactical vests (Armor). Shoulders (Back): Slings","description":"","headingLevel":2,"fileSlug":"inventory"},{"title":"Quests","pageTitle":"Quests","breadcrumb":"Quests","url":"/mechanics/foundational/quests/","content":"Quests are structured objectives within the game world that provide characters with goals, challenges, and rewards. Each quest is tracked using tallies, which represent knowledge, preparation, and world consequences. A quest begins when failure or success would meaningfully change the character or situation.","description":"","headingLevel":1,"fileSlug":"quests"},{"title":"1. Plan Tally","pageTitle":"Quests","breadcrumb":"Quests › Quest Structure › 1. Plan Tally","url":"/mechanics/foundational/quests/#1-plan-tally","content":"Represents preparation, strategy, or knowledge required to execute the quest. Default length: 5 marks Must be completed before attempting the resolution roll. Effect: Missing plan marks hinders all resolution rolls for the quest by -1 per missing mark. Completing the plan tally reduces the countdown by 1 mark.","description":"","headingLevel":3,"fileSlug":"quests"},{"title":"2. Location Tally","pageTitle":"Quests","breadcrumb":"Quests › Quest Structure › 2. Location Tally","url":"/mechanics/foundational/quests/#2-location-tally","content":"Represents discovery of the quest’s endpoint or key sites. Default length: 5 marks Must be completed to attempt the quest resolution. Effect: Completing the location tally reduces the countdown by 1 mark.","description":"","headingLevel":3,"fileSlug":"quests"},{"title":"3. Countdown (Consequence) Tally","pageTitle":"Quests","breadcrumb":"Quests › Quest Structure › 3. Countdown (Consequence) Tally","url":"/mechanics/foundational/quests/#3-countdown-consequence-tally","content":"Not all quests need a countdown — ie: Becoming a Blade Master does not need a countdown (there is no time limit). Finding a lost person should. (They could die or be lost forever.) Tracks consequences that can lead to automatic quest failure. Default length: 10 marks (2 tallies) Triggers: Only advances when specific in-game events or consequences occur (e.g., enemy progress, faction actions, failed objectives). Effect of Completion: Completing plan, location, or quest steps reduces the countdown by 1 mark per completed element. Failure Condition: When all marks are filled, the quest fails automatically and the consequence happens.","description":"","headingLevel":3,"fileSlug":"quests"},{"title":"Interaction with Insights","pageTitle":"Quests","breadcrumb":"Quests › Interaction with Insights","url":"/mechanics/foundational/quests/#interaction-with-insights","content":"Quests are advanced by insights found in the world: - Goal insights contribute to Plan tallies. - Location insights contribute to Location tallies. - Countdown insights contribute to the Countdown tallies. Players decide which insights apply to which tallies when discovered. Faction-driven quests may advance independent of player knowledge, triggering consequences that fill Countdown marks without player intervention.","description":"","headingLevel":2,"fileSlug":"quests"},{"title":"Multi-Step Quests","pageTitle":"Quests","breadcrumb":"Quests › Multi-Step Quests","url":"/mechanics/foundational/quests/#multi-step-quests","content":"Quests may have multiple intermediate steps. Each step completed: - Counts toward the Plan tally if preparation was required. - Reduces the Countdown tally by 1 mark. Allows for branching or staged objectives, giving players opportunities to actively mitigate consequences.","description":"","headingLevel":2,"fileSlug":"quests"},{"title":"Quest Structure","pageTitle":"Quests","breadcrumb":"Quests › Quest Structure","url":"/mechanics/foundational/quests/#quest-structure","content":"Each quest has the following components: Goal — The intended outcome the player must achieve to complete the quest. Reward — The benefit or consequence gained when the quest is resolved successfully. Rewards should return at minimum 1 new tag. Other rewards should be award based on the quest. Tallies — Markers that track progress, preparation, and urgency. There are usually three tallies: Plan, Location, and Countdown. Steps — Optional intermediate objectives within a quest. Completing a step can affect tallies and countdowns. Consequence — If the quest fails, this happens. Consequences should also add a new negative affecting tag.","description":"","headingLevel":2,"fileSlug":"quests"},{"title":"Resolution","pageTitle":"Quests","breadcrumb":"Quests › Resolution","url":"/mechanics/foundational/quests/#resolution","content":"The resolution roll represents the character’s attempt to complete the quest. Prerequisites: - Plan tally fully completed (or risk penalties). - Location tally fully completed. Modifiers: - Each missing Plan mark: -1 penalty to resolution roll. - Fully completed Plan tally: ease all resolution rolls by +1. - Countdown remaining does not affect rolls directly but represents the ongoing world pressure.","description":"","headingLevel":2,"fileSlug":"quests"},{"title":"Time","pageTitle":"Time","breadcrumb":"Time","url":"/mechanics/foundational/time/","content":"Time determines everything. How long have I been asleep? How long did it take me to travel to the store? Do I have enough time to watch this show? Time in Tag and Tally is represented by 6 shifts, in a 24 hour day (if your day is longer or shorter you can determine this for yourself). Each shift is 4 hours long. 4 shifts are required to be active shifts containing 10 Action Points. The other 2 shifts are required to be Downtime Shifts, they contain 4 Downtime Points. If you use an Action in a Downtime point you will retain for the next entire day Exhausted tag which will hinder all activates for the next day until you sleep at least 4 hours (1 full shift). If you do take another Action in the same period your Exhaustion tag goes up one Tier hindering by an additional level. If your Exhaustion tag reaches Level 4, any additional Exhaustion cause a Lingering Trauma which will hinder additional actions based on the injury. You can rearrange the shifts as you see fit, we recommend: | Time ","description":"","headingLevel":1,"fileSlug":"time"},{"title":"Action Points","pageTitle":"Time","breadcrumb":"Time › Action Points","url":"/mechanics/foundational/time/#action-points","content":"Action points represent the number of scenes, rooms, blocks, hexes a character or group may do in any given day. Traveling to a location can take up a number of AP slots, but you do not need to incur an additional cost to handle the events at your destination. Anything in the scene or destination does not cost an additional point, unless it leads you to another location (ie: on a street block and you go into a building — the scene has changed)","description":"","headingLevel":2,"fileSlug":"time"},{"title":"Downtime Points","pageTitle":"Time","breadcrumb":"Time › Downtime Points","url":"/mechanics/foundational/time/#downtime-points","content":"Downtime Points represent the number of activities you can do that constitute resting in safe zone allowing you to heal wounds. You do not have to sleep, but it is recommended each character sleep 4 hours so they wake up Refreshed.","description":"","headingLevel":2,"fileSlug":"time"},{"title":"Wounds","pageTitle":"Wounds","breadcrumb":"Wounds","url":"/mechanics/foundational/wounds/","content":"Wounds are tags that hinder appropriate actions and tasks. !wounds This wound is a \\descriptor \\type of mark located on \\the body part that \\specific mechanical detriment. There are 4 types of wounds — Strain, Lingering Trauma, Debilitating Injury and Lasting Scars. Strains are minor wounds, small scraps cuts and bruises things that are annoying but do not have any mechanical determents to your abilities. Linger Traumas and Debilitating Injuries are wounds that hamper your ability to certain activities. You need to create a wound sentence for these injuries to determine location and the mechanical disadvantage it adds. When healed these sentences leave behind no traces they once existed. Lasting Scars are major wounds that if not treated properly can kill or end a characters career as an 'adventurer'. They require a sentence, but when healed they leave behind another sentence that remains with the character permanently that hinders some form of action. This new sentences does not count","description":"","headingLevel":1,"fileSlug":"wounds"},{"title":"Healing","pageTitle":"Wounds","breadcrumb":"Wounds › Healing","url":"/mechanics/foundational/wounds/#healing","content":"Healing Life Magic is always a ritual and cannot be cast in combat. Healing is a specific application of Life magic that interacts with Wounds. Not all Life spells heal, and Life magic that does not explicitly restore Wounds does not interact with this system. Healing is a deliberate effect that restores or stabilizes wounds. It is not limited to Life magic—spells using other Aspects or Bases may also heal, but the method, cost, and risks can vary. Life-based healing is precise, ritual-only, and cannot be used in combat. Other Aspects (e.g., Fire, Order) may heal in combat or under duress, but may leave lasting scars or cause other mechanical consequences. All Healing effects follow the rules for Wounds recovery and Lasting Scars unless explicitly stated otherwise.","description":"","headingLevel":2,"fileSlug":"wounds"},{"title":"Lasting Scars","pageTitle":"Wounds","breadcrumb":"Wounds › Lasting Scars","url":"/mechanics/foundational/wounds/#lasting-scars","content":"!wound Lasting Scar The Lasting Scar is a \\descriptor \\type of mark located on \\the body part that \\specific mechanical detriment. Lasting Scars heal over a Long Downtime period of recovery. When healed the Lasting Scar does not regenerate missing body parts. The character applies a new tag describing how they've overcome the limitation. If a character has 3 Lasting Scars at any one time it is the end of the game for the character. The player may choose to retire the character or the character may die, but it is the player's choice. 3 Lasting Scars means it is near impossible for the character to continue functioning on an adventure. Healed Lasting Scars do not count against this number. They leave behind a permanent mark but they don't hinder the characters performance any longer.","description":"","headingLevel":2,"fileSlug":"wounds"},{"title":"Treating Wounds","pageTitle":"Wounds","breadcrumb":"Wounds › Treating Wounds","url":"/mechanics/foundational/wounds/#treating-wounds","content":"A wound can be treated in the field by successfully passing a Level 5 Field treatment check. For each attempt after the first the task is hindered by one for each additional try. On a successful check you may heal 1 strain, or downgrade 1 other wound except a Lasting Scar. You may Field treat a wound only directly after combat. You may not try again in another scene. Wounds can be treated by someone with the appropriate knowledge (doctor/barber etc) with a Level 3 Treat Injury check. For each attempt after the first the task is hindered by one for each additional try. On a successful check strains and lingering traumas are removed or one debilitating injury is downgraded to a lingering trauma. You may only be treated by a professional once per session. Wounds may be healed by magic by successfully passing a Level 3 Treat Injury check. On a successful check all wound except a Lasting Scar are healed, or 1 Lasting Scar that can be healed is healed. However, if a Lasting Scar with a missi","description":"","headingLevel":2,"fileSlug":"wounds"},{"title":"Crafting","pageTitle":"Crafting","breadcrumb":"Crafting","url":"/mechanics/optional/crafting/","content":"There are four phases of crafting. Harvesting — the act of gathering the necessary materials to craft an item. Crafting — the act of manufacturing the item with the materials acquired. Crafting cannot typically be done out in the field and requires specialized equipment. The exception to the rule is crafting consumables. Augmenting — the act of changing or enhancing an existing item with new materials acquired. Augmenting cannot typically be done out in the field and requires specialized equipment. Most items can be augmented, the exception to the rule is consumables. Salvaging — the act of destroying a magical item in order to salvage its properties. Salvaging cannot typically be done out in the field and requires specialized equipment. Most items can be salvaged, the exception to the rule is consumables. Repairing is a specialized Augmenting task where the user does not apply anything new but fixes a broken item.","description":"","headingLevel":1,"fileSlug":"crafting"},{"title":"Augmenting","pageTitle":"Crafting","breadcrumb":"Crafting › Augmenting","url":"/mechanics/optional/crafting/#augmenting","content":"Augmenting is much like crafting, except you are changing the properties of your already crafted item with new and/or different features. You may choose to repair an item as well. You do not need to add any additional materials, but it is assumed you have the materials to repair the item. There will be no rarity addition for a repair. Modify your item sentence. To augment an item. You must roll a augment check against the items level plus the rarity the new item (DC = (Level + rarity) \\* 3). If you failed the check you may try again hindering the task by 2 for each new attempt. | Rarity | Modifier | | --------- | -------- | | Common | 1 | | Uncommon | 2 | | Rare | 3 | | Legendary | 4 | | d20 | Result | Details | | ------------ | ------------ | ------------------------------------------------------------------------------- | | 1 | Fail, and | You failed to augment the item and you lose the raw material. | | 2 to DC-6 | Fail, but | You failed to augment the item but you didn't lose any m","description":"","headingLevel":2,"fileSlug":"crafting"},{"title":"Crafting","pageTitle":"Crafting","breadcrumb":"Crafting › Crafting","url":"/mechanics/optional/crafting/#crafting","content":"Crafting takes some imagination from the player as there is no real set recipe system for crafting gear. The player decides what the item should do based on the creature (or creatures) the base item came from. If you are playing with a party, the party should agree that it is a viable idea. To craft an item. You must roll a crafting check against the base items (typically a metal, wood, leather, fiber, liquid, etc.) level plus the rarity of the second magical item (DC = (Level + rarity) \\* 3). If you failed the check you may try again hindering the task by 2 for each new attempt. | Rarity | Modifier | | --------- | -------- | | Common | 1 | | Uncommon | 2 | | Rare | 3 | | Legendary | 4 | | d20 | Result | Details | | ------------ | ------------ | ----------------------------------------------------------------------------- | | 1 | Fail, and | You failed to craft the item and you lose the materials | | 2 to DC-6 | Fail, but | You failed to craft the item but you didn't lose any materials","description":"","headingLevel":2,"fileSlug":"crafting"},{"title":"Creature Parts","pageTitle":"Crafting","breadcrumb":"Crafting › Harvesting › Creature Parts","url":"/mechanics/optional/crafting/#creature-parts","content":"Essence Essence can be harvest from any creature. The essence of a creature is some magical property in which that creature possessed or was capable of in life. The essence can be extracted instead of a part if you wish to augment this ability onto an existing item without altering the physical form of the item. The party has just killed a dragon, and they want to harvest the breath sac, scales and the essence. The dragon was Level 5. They must roll against a DC of 15 for the breath sac. 1d20: \\13 = 13 → failed breath sac harvest If they were to try again the task would be a level 7 which is a DC of 21 and impossible without any tags applied to ease the task.","description":"","headingLevel":3,"fileSlug":"crafting"},{"title":"Harvesting","pageTitle":"Crafting","breadcrumb":"Crafting › Harvesting","url":"/mechanics/optional/crafting/#harvesting","content":"Name is a \\rarity\\ \\descriptor\\ \\plant\\ that \\special\\. To Harvest raw materials roll a harvest check against the DC of the creature or resource being harvested (Level \\* 3) on the first item to be harvested. If the resource was not destroyed in a failed attempt, you may try again. For each subsequent try or item on the harvest list the harvesting task is hindered by two. | d20 | Result | Details | | ------------ | ------------ | -------------------------------------------------------------------- | | 1 | Fail, and | You failed to harvest the item and destroyed the resource | | 2 to DC-6 | Fail, but | You failed to harvest the item but the node is intact | | DC-5 to DC-1 | Success, but | Successfully harvested the item but the item level is lowered by one | | DC to DC+4 | Success | Successfully harvested the item of equal level to the source | | DC+5 + | Success, and | Successfully harvested the item and the level is raised by one |","description":"","headingLevel":2,"fileSlug":"crafting"},{"title":"Resources","pageTitle":"Crafting","breadcrumb":"Crafting › Harvesting › Resources","url":"/mechanics/optional/crafting/#resources","content":"Name is a \\rarity\\ \\descriptor\\ \\resourceType\\ that \\special\\. | d6 | Resource Type | Used in | | --- | ------------- | --------------------- | | 1 | Ore | Armor, Weapons, Items | | 2 | Wood | Weapons, Traps, Items | | 3 | Fiber | Armor, Traps, Items | | 4 | Liquid | Consumables | | 5 | Plants | Consumables, Traps | | 6 | Roll again | — | | d4 | Rarity | | --- | --------- | | 1 | Common | | 2 | Uncommon | | 3 | Rare | | 4 | Legendary |","description":"","headingLevel":3,"fileSlug":"crafting"},{"title":"Salvaging","pageTitle":"Crafting","breadcrumb":"Crafting › Salvaging","url":"/mechanics/optional/crafting/#salvaging","content":"To salvage an item. You must roll salvaging check against the items level. If you failed the check you may try again hindering the task by 2 for each new attempt. | d20 | Result | Details | | ------------ | ------------ | ----------------------------------------------------------- | | 1 | Fail, and | You failed to salvage the item and destroyed it | | 2 to DC-6 | Fail, but | You failed to salvage the item but it was not damaged | | DC-5 to DC-1 | Success, but | Successfully salvaged the item but the property is dimished | | DC to DC+4 | Success | Successfully salvaged the item with the intended property | | DC+5 + | Success, and | Successfully salvaged the item with two properties | On a successful salvaging decide what property was salvaged from the item. This property may be applied to an existing item with a Level 5 Augmenting task.","description":"","headingLevel":2,"fileSlug":"crafting"},{"title":"Crafting","pageTitle":"Crafting","breadcrumb":"Crafting","url":"/mechanics/optional/downtime/","content":"Downtime points are reduced to 4 for sake of ease. You can use 1 point to do 1 thing for 1 hour. Travel to and from a location to preform a downtime task, plus the time spent is recorded off screen, you don't travel there as you would during the day. We Recommend that you only do 1 travel type downtime activity in any given downtime if you are going for realism. | Activity | Cost | Limits | Notes | | ----------- | ---- | --------------------------------- | ----------------------------------- | | Sleep | 1 | | 4 hours recommended | | Crafting | 1 | Safe Zone or appropriate location | See Crafting Rules in Tag and Tally | | Research | 1 | Safe Zone or appropriate location | See Research Rules | | Repair | 1 | Safe Zone or appropriate location | See Repair Rules in Tag and Tally | | Study | 1 | Safe Zone or appropriate location | See Study Rules | | Meditation | 1 | | See Meditation Rules | | Socializing | 1 | | See Socializing Rules | | Drinking | 1 | | See Drinking Rules | | Gambling | ","description":"","headingLevel":1,"fileSlug":"downtime"},{"title":"Dinner","pageTitle":"Crafting","breadcrumb":"Crafting › Dinner","url":"/mechanics/optional/downtime/#dinner","content":"You may cook a meal, go out to a restaurant. Sending 1 hour at a dinner downtime activity yields the \\Well fed tag for the following day. You may only spend 1 hour at Dinner.","description":"","headingLevel":2,"fileSlug":"downtime"},{"title":"Drinking","pageTitle":"Crafting","breadcrumb":"Crafting › Drinking","url":"/mechanics/optional/downtime/#drinking","content":"Drinking gives you the \\Liquid Courage tag for the following day. You may only have 1 Tier of this, no matter how much you drink. For every hour you drink you gain a Tier of Hangover (up to 4). Your first hour of drinking does not yield a Hangover, only after a second hour do you accumulate the Tier (# hours drinking - 1 = Tier of Hangover) The \\Hangover Tag hinders all mental actions. The condition can be reduced by 1 Tier after 2 travel points have been used for each tier.","description":"","headingLevel":2,"fileSlug":"downtime"},{"title":"Gambling","pageTitle":"Crafting","breadcrumb":"Crafting › Gambling","url":"/mechanics/optional/downtime/#gambling","content":"For every hour make one bet and roll 1d20 | Bet | Reward | Loss | | --------------- | ------------------------------- | ------------------------------- | | Choose a number | Increase your wealth tally by 2 | Decrease your wealth tally by 1 | | Even or Odd | Increase your wealth tally by 1 | Decrease your wealth tally by 1 | When your wealth tally reaches 5 increase your wealth by 1 and the reset your tally to 0. If you drop to 0 wealth tally decrease your wealth by 1.","description":"","headingLevel":2,"fileSlug":"downtime"},{"title":"Meditation","pageTitle":"Crafting","breadcrumb":"Crafting › Meditation","url":"/mechanics/optional/downtime/#meditation","content":"Meditating for 1 hour provides you with a \\Zen tag for the following day. You may only meditate for 1 hour a night.","description":"","headingLevel":2,"fileSlug":"downtime"},{"title":"Research","pageTitle":"Crafting","breadcrumb":"Crafting › Research","url":"/mechanics/optional/downtime/#research","content":"Pick a topic to research. It may be a Plan or Location for a quest or faction, a strength or weakness of a creature, a secret for a faction or NPC, or something else your character is interested in. For every hour you spend researching you gain 1 Tally mark towards only that objective. You may only research up to 4 hours a night.","description":"","headingLevel":2,"fileSlug":"downtime"},{"title":"Sleep","pageTitle":"Crafting","breadcrumb":"Crafting › Sleep","url":"/mechanics/optional/downtime/#sleep","content":"Sleeping gives you a \\Refreshed Tag for the following day. No matter how many hours you sleep the tag does not tier. In addition to the \\Refreshed Tag, for every 4 hours of sleep a character may heal one additional type of injury (all strains, 1 lingering trauma, or downgrade 1 debilitating injury).","description":"","headingLevel":2,"fileSlug":"downtime"},{"title":"Socialization","pageTitle":"Crafting","breadcrumb":"Crafting › Socialization","url":"/mechanics/optional/downtime/#socialization","content":"Pick an NPC or PC to build your relationship with. For every hour you spend with this character you earn 1 Tally for your Relationship tag. You can only socialize for 4 hours a night. You may spend time with another character, drinking, gambling, or go to dinner. (or some other socialization as long as it doesn't require much physical activity). Use the appropriate rules to handle outcomes as well as increase your reputation.","description":"","headingLevel":2,"fileSlug":"downtime"},{"title":"Study","pageTitle":"Crafting","breadcrumb":"Crafting › Study","url":"/mechanics/optional/downtime/#study","content":"Pick a skill or ability to learn. You may choose an existing one, or one that you do not know. For a skill or ability you do not know you may add it to your character sheet, but you may not use it until you have earned 5 tallies and made it a Tier 1 ability. For every hour you spend studying you gain 1 Tally mark towards your next Tier. You may only study up to 4 hours a night.","description":"","headingLevel":2,"fileSlug":"downtime"},{"title":"Workout","pageTitle":"Crafting","breadcrumb":"Crafting › Workout","url":"/mechanics/optional/downtime/#workout","content":"For every 1 hour you spend working out you may add a tally to one physical skill, ability or trait on your character, or if you are working towards some other physical ability you are trying to learn. For every hour you workout, you also gain a \\Sore Muscles tag which hinders all physical activity. Your first hour doesn't cost you this, but for every hour afterwards you gain a tier of the tag. (# hours working out - 1 = Tier of Sore Muscles) \\Sore Muscles reduces by 1 tier for every 2 tiers of travel points spent.","description":"","headingLevel":2,"fileSlug":"downtime"},{"title":"Factions","pageTitle":"Factions","breadcrumb":"Factions","url":"/mechanics/optional/factions/","content":"!faction Faction Name is a \\descriptor \\organization type that \\core function or purpose and \\has a goal. Despite their outward reputation, they \\have a secret The Location of a faction's headquarters is unknown to the common public and must be found via insights in game unless the Character has a connection to it. Every secret a faction must also be learned to be useful to any in game play. Goals should be treated like quests. And as Faction Goals can be completed without the interference of a player character they will use a phase timer. Each phase has a tally of 5 and must be completed before work can begin on the next phase. The countdown timer resets when a new phase begins. But if the countdown timer is reached first, then both the countdown timer and the phase tally are reset and the phase begins anew.","description":"","headingLevel":1,"fileSlug":"factions"},{"title":"Goals/Quests","pageTitle":"Factions","breadcrumb":"Factions › Goals/Quests","url":"/mechanics/optional/factions/#goalsquests","content":"Factions operate on a life of their own. Their goals progress through six phases leading to a final End state. This progression happens regardless of player involvement, though player intervention (or inter-faction conflict) can sabotage this progress. A faction's goal is always in progress, at the start of the game it is in Phase 1. And as Insights are found for the faction, things keep going even if the players never interact or know of the faction or their plots. This allows the world to feel real and lived in. Each Phase if the goal is unknown to the players has a Tally of 5. When 5 is reached the next phase starts, and the Tally resets to zero. If the players find out about the phase through Insights, then it shifts to a Plan/Location of a Quest with a Tally of 5 and a Countdown Timer of 10. If the phase reaches the tally of 5 it continues on to the next phase and both the Tally and Countdown reset to 0. If the countdown is reached before the next the next phase, the Tally is rese","description":"","headingLevel":2,"fileSlug":"factions"},{"title":"The Thwart Mechanism (Inter-Faction Interference)","pageTitle":"Factions","breadcrumb":"Factions › The Thwart Mechanism (Inter-Faction Interference)","url":"/mechanics/optional/factions/#the-thwart-mechanism-inter-faction-interference","content":"When one faction (Faction A) is working against each other faction (Faction B), Faction A's insights affect the tallies of Faction B. When a Goal or Plan insight for the Faction is discovered, it serves a dual purpose: Tally Progress: It fills 1 mark on the Faction A's current Tally. Countdown Acceleration: It fills 1 mark on Faction B's Countdown Tally (representing the aggressive suppression methods speeding up the \"end-state\" of the conflict). The Reset Condition: If Faction A's Tally (5 marks) is completed before Faction B's reaches their next Tally Stage: The Faction B's Phase Tally resets to zero (their current task is sabotaged). The Countdown Clock does not reset (the time lost is still gone). Faction A's Tally resets to zero.","description":"","headingLevel":2,"fileSlug":"factions"},{"title":"NPC Interactions","pageTitle":"NPC Interactions","breadcrumb":"NPC Interactions","url":"/mechanics/optional/npc-interactions/","content":"Every NPC has a Permanent Disposition (how they feel about you generally) and a Temporary Attitude (their current mood). Permanent Disposition: Provides a baseline Ease (-) or Hinder (+) to the Task Level. Temporary Attitude: Determined by the Drift Roll at the start of a scene.","description":"","headingLevel":1,"fileSlug":"npc-interactions"},{"title":"Interactions","pageTitle":"NPC Interactions","breadcrumb":"NPC Interactions › Interactions","url":"/mechanics/optional/npc-interactions/#interactions","content":"A typical NPC will start at indifferent when meeting an NPC. Based on society and faction expectations adjust the relationship. Relationships changed based on the interactions. When interacting with an NPC any checks should be eased or hindered by the indicated amount. First Interaction: When encountering an NPC for the first time start at indifferent and adjust your relationship based on society and faction expectations. This is where your character will start the relationship. Following Interactions: Roll 2d6. | 2d6 | Drift | | ----- | ------------ | | 2-3 | Down 2 steps | | 4-5 | Down 1 step | | 6-8 | No change | | 9-10 | Up 1 step | | 11-12 | Up 2 steps | This is a temporary state and will only last for this scene unless you make a drastic change in the relationship status and it changes permanently. For any modifiers in social interactions use the original disposition, only their current attitude towards you is changed as their mood has. | Steps | Disposition | Attitude | | ----- ","description":"","headingLevel":2,"fileSlug":"npc-interactions"},{"title":"Pathways","pageTitle":"NPC Interactions","breadcrumb":"NPC Interactions › The Conversation › Pathways","url":"/mechanics/optional/npc-interactions/#pathways","content":"If you approach the NPC first: | 1d10 | You Approach Pathways | | ---- | --------------------------------------------------------------- | | 1 | Offering Aid: Can I help you (the NPC) with something? | | 2 | Trade: Do you have wares or goods to sell? | | 3 | Streetwise: Have you heard any rumors? | | 4 | Interrogation: Do you know anything about a specific topic? | | 5 | Eavesdropping: Listen in on a conversation. | | 6 | Networking: Can you introduce me to ...? | | 7 | Intimidation: Try to forcibly make an NPC do something | | 8 | Contracting: I want to hire/consult with you. | | 9 | Restoration: Trying to get into their good graces. | | 10 | Advisor: What would you do in ...? | Use the following results for the NPC Interactions | d20 | Result | Details | | ------------ | ------------ | ------------------------------------------------------------------------------------- | | 1 | Fail, and | You fail in your attempt. The NPC is insulted. Decrease permanent Disposition 1 step. | | 2 to ","description":"","headingLevel":3,"fileSlug":"npc-interactions"},{"title":"The Conversation","pageTitle":"NPC Interactions","breadcrumb":"NPC Interactions › The Conversation","url":"/mechanics/optional/npc-interactions/#the-conversation","content":"You are more than welcome to write/play out actual dialog and have a conversation with your NPCs. Or if you aren't feeling like a novelist or story teller today you can opt to choose a more mechanical method below. Pick a Pathway.","description":"","headingLevel":2,"fileSlug":"npc-interactions"},{"title":"Spellcasting","pageTitle":"Spellcasting","breadcrumb":"Spellcasting","url":"/mechanics/optional/spellcasting/","content":"Any player character has access to magic if they so desire. If a character has a tag that specifies they have access to a specific Aspect of magic the tag eases the task. All characters if they have access to magic, have an MAI (Magical Aptitude Index). If a spells level is below the MAI of a caster, no roll is needed. If a spell's level is at or above the MAI roll is required to cast the spell. The amount over the MAI also hinders the casting roll see the table below | Difference | Steps Hindered | | ---------- | -------------- | | 1-3 | 1 step | | 4-6 | 2 steps | | 7-9 | 3 steps |","description":"","headingLevel":1,"fileSlug":"spellcasting"},{"title":"Artifacts","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Casting a Spell › Artifacts","url":"/mechanics/optional/spellcasting/#artifacts","content":"| Artifact | Step Modifier | MAI Check | Notes on Activation / Triggers | | ------------- | ------------- | ----------- | ------------------------------------------------------------------------------------------------------------------------- | | Ritual | Eases 2 | At creation | Slowest, safest; nothing left to chance; casting failure just fails, no mishap; can be left unattended once complete | | Encoded | Eases 1 | At creation | Prebuilt runes, code, circuits, glyphs, or tech; triggers require no MAI check; can be activated remotely or by a trigger | | Channeled | Neutral (0) | At casting | Verbal, gestural, singing, or other interruptible forms; skill and focus matter; triggers ignored if pre-cast | | Manifestation | Hinder 1 | At casting | Pure willpower; immediate, flexible, and high risk; cannot be outsourced; triggers ignored if pre-cast | The Difference between Ritual and Encoded: | Ritual | Encoded | | -------------------------------- | -------------------- | | Perfect execut","description":"","headingLevel":3,"fileSlug":"spellcasting"},{"title":"Aspects","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Spell Creation › Aspects","url":"/mechanics/optional/spellcasting/#aspects","content":"Air, Earth, Water, Fire Life, Death Mind, Time, Space, Sound, Illusion Shadow, Light","description":"","headingLevel":3,"fileSlug":"spellcasting"},{"title":"Base","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Spell Creation › Base","url":"/mechanics/optional/spellcasting/#base","content":"Order — structure and stability Chaos — Motion and transformation Void — Nullification and isolation Spirit — Conscious link","description":"","headingLevel":3,"fileSlug":"spellcasting"},{"title":"Blood Magic","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Casting a Spell › Blood Magic","url":"/mechanics/optional/spellcasting/#blood-magic","content":"Blood magic is rare and evil. Blood magic requires the user to specifically take the tag \"Uses Blood Magic\" in order to actually have access to it. It may be applied at Character Creation but must be earned through a Character Arc at any other time. To cast a spell with Blood Magic you must sacrifice part of yourself or another living creature of the appropriate level. This sacrifice will ease the spell casting by two and the target sacrifice will gain 1 lingering trauma wound. If the living creature is below level 3 it is instantly killed. The damage type for this is necrotic.","description":"","headingLevel":3,"fileSlug":"spellcasting"},{"title":"Casting a Spell","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Casting a Spell","url":"/mechanics/optional/spellcasting/#casting-a-spell","content":"Spells are cast in one of four ways using Artifacts. These artifacts define how a spell is executed and influence its ease, risk, and activation.","description":"","headingLevel":2,"fileSlug":"spellcasting"},{"title":"Example Spells","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Spell Creation › Example Spells","url":"/mechanics/optional/spellcasting/#example-spells","content":"Wish Sentence: Wish is a \\complex \\Chaos spell that \\replicates the effect of any other spell or creates nearly any outcome. Axes Points: Aspect: Time (high-risk) → 3 points Type: Control (high-risk) → 3 points Base: Chaos → 4 points Base Level: 3 + 3 + 4 = 10 → Level 4 Power Modifier (PM): Scope: World-altering / other plane → 5 Final Spell Level: 4 + 5 = Level 9 Temporal Inferno Sentence: Temporal Inferno is a \\volatile \\Chaos spell that \\burns and distorts time to damage and control enemies. Axes: Base: Chaos (4 points) Primary Aspect: Fire (2 points) Primary Type: Damage (2 points) Additional Aspect: Time (3 points) Additional Type: Control (3 points) Total Additional Axes: 2 (Time + Control) Additional Axis Cost: 1st additional axis → 1 point 2nd additional axis → 2 points Total Additional Axis Cost = 3 points Total Points Calculation: Base + Primary Axes: 4 + 2 + 2 = 8 Additional Axes Points: 3 + 3 = 6 Additional Axis Cost: 3 Total Points = 17 Level Mapping: 17 points → Spell Lev","description":"","headingLevel":3,"fileSlug":"spellcasting"},{"title":"Lingering Traumas","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Casting a Spell › Lingering Traumas","url":"/mechanics/optional/spellcasting/#lingering-traumas","content":"| Roll (d6) | Descriptor | Type of Mark | Body Part | Mechanical Detriment | | :-------- | :--------- | :------------------ | :--------------- | :------------------------------ | | 1 | weeping | obsidian vein | the casting hand | hinders fine motor skills | | 2 | necrotic | sunken brand | the chest | hinders all physical tasks | | 3 | pale | spiderweb bruise | the throat | hinders all social interactions | | 4 | rhythmic | pulsing scar | the temples | hinders all mental tasks | | 5 | jagged | crystalline fissure | the forearm | hinders all spellcasting | | 6 | cold | silver-black stain | the eyes | hinders all senses |","description":"","headingLevel":3,"fileSlug":"spellcasting"},{"title":"Magical Aptitude Index (MAI)","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Magical Aptitude Index (MAI)","url":"/mechanics/optional/spellcasting/#magical-aptitude-index-mai","content":"The Magical Aptitude Index (MAI) measures a being’s innate connection to the fundamental forces of magic. It represents potential — how easily one can perceive, channel, and manipulate aetheric energy. A higher MAI reflects a naturally resonant essence, often tied to birthright, lineage, or cosmic phenomena. MAI begins with a base value set by species and modified by subspecies, descriptor, type, and specialization. Ultimately, MAI determines the ceiling of a caster’s magical capability, shaping both the scope and stability of their spell craft. Each Species has a base MAI to start a character with. Sub-species may modify this number. For each Magical tag in the Character sentence you add +1 to the MAI number. (so up to +3 — descriptor, type, and specialty) Sometimes when a world has only species that considered human (i.e.: Earth) the base MAI is regulated by the type. If a Type and a Species both have a Base MAI use the highest of the two (do not combine).","description":"","headingLevel":3,"fileSlug":"spellcasting"},{"title":"Notes","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Casting a Spell › Notes","url":"/mechanics/optional/spellcasting/#notes","content":"MAI Checks: Only required at the relevant stage (creation for Rituals/Encoded, casting for Channeled/Manifestation). Triggered Spells: Any spell triggered by a device, rune, or ability ignores MAI checks. Only the pre-established creation result applies. Ritual Failures: If a Ritual fails at casting (activation), it simply fails. No backfire or mishap occurs. Note: Success, but and Fail, and just Fail. Step Modifier: This modifies the difficulty of the casting roll or creation roll depending on artifact type. | d20 | Result | Details | | ------------ | ------------ | -------------------------------------------------------------- | | 1 | Fail, and | Fail, and Roll on the Mishap table | | 2 to DC-6 | Fail, but | The spell fails, but nothing backfires or goes wrong | | DC-5 to DC-1 | Success, but | Success, but it backfires and hindering your next casting roll | | DC to DC+4 | Success | The spell goes off exactly as you expected | | DC+5 + | Success, and | Successfully cast the spell and ","description":"","headingLevel":3,"fileSlug":"spellcasting"},{"title":"Spell Creation","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Spell Creation","url":"/mechanics/optional/spellcasting/#spell-creation","content":"Spells have a sentence like all other things in Tag & Tally. !magic Spell Name is a \\descriptor\\ \\base\\ spell that \\does something\\.","description":"","headingLevel":2,"fileSlug":"spellcasting"},{"title":"Spell Level","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Spell Creation › Spell Level","url":"/mechanics/optional/spellcasting/#spell-level","content":"To determine a spell’s base level, assign points for three factors: Aspect, Type, and Base. Use the predefined point values, sum the points from all factors to get a total. Compare the total to the Level mapping. The resulting Level reflects the spell’s base complexity, power, and risk. Aspect and Type are called an Axis, every spell has 2 Axis as a base (aspect and type). | Aspect | Points | | ---------------------------------------------- | ------ | | earth, air, water, death, illusion (low-risk) | 1 | | fire, mind, light, sound (moderate) | 2 | | shadow, time, life, space (high-risk/volatile) | 3 | | Type | Points | | ------- | ------ | | Damage | 2 | | Control | 3 | | Summon | 3 | | Ward | 2 | | Counter | 3 | | Base | Points | | ------ | ------ | | Order | 1 | | Spirit | 2 | | Chaos | 4 | | Void | 3 | A spell can have multiple aspects and types but only one base. Combining multiple types or aspects requires that the base ALWAYS be chaos. You may only add up to 3 additional axes (as","description":"","headingLevel":3,"fileSlug":"spellcasting"},{"title":"Spell Types","pageTitle":"Spellcasting","breadcrumb":"Spellcasting › Spell Creation › Spell Types","url":"/mechanics/optional/spellcasting/#spell-types","content":"Damage — Harmful effects Counter — Nullifies or prevents effects Control — Manipulates forces/objects Summon — Calls forth creatures or objects Ward — Protection-based effects","description":"","headingLevel":3,"fileSlug":"spellcasting"},{"title":"Travel","pageTitle":"Travel","breadcrumb":"Travel","url":"/mechanics/optional/travel/","content":"There are three types of travel that can be used in Tag & Tally. Wilderness Urban Dungeon The number of Points is limited. | Pace | Slow | Normal | Fast | | -------------- | ---- | ------ | ---- | | Wilderness | 4 | 5 | 6 | | Urban | — | 4 | 5 | | With Transport | +1 | +2 | +3 | | Dungeon | — | 10 | — | Slow Travel allows scouting, foraging and hunting during Wilderness Travel. Fast Travel adds the Exhaustion condition tag for the Next Day on every Scene. Transportation cannot be used inside a dungeon Wilderness travel is based on costs of the terrain you are entering before needing to rest either in a safe zone or in camp. Urban travel is the number of point that can be completed in a given day before needing to return home to rest. Dungeon travel is the number of rooms in a regular sized dungeon that can be encountered before needing to rest.","description":"","headingLevel":1,"fileSlug":"travel"},{"title":"Dungeon","pageTitle":"Travel","breadcrumb":"Travel › Dungeon","url":"/mechanics/optional/travel/#dungeon","content":"Setup a Dungeon: Generate a dungeon name and theme Generate Objective Roll a scene status Generate the number of rooms by rolling 1d6+4 (5-10). - The first room always has an entrance and 3 open exits and does not count against your number of rooms. - Hidden rooms do not count against the number of rooms. - The object room does not count against the number of rooms. After rolling the last room roll again to create the final room and your objective. Choose 2 different colored d6. One to be the X axis , the second to be Y axis. Roll the 2d6 and draw a room with those dimensions and an open exit on each side. There is nothing in this starter room and does not count against the number of rooms to the dungeon Pick an exit and roll 2d6, then draw the next room. Roll number of exits for the room 1d4-1. Roll for contents and resolve the encounter. If there are rooms left in the total count go to #4 If there are no rooms left choose any remaining exit that is not opened and create a 5x5 room wi","description":"","headingLevel":2,"fileSlug":"travel"},{"title":"Entering a Scene, Hex or Room","pageTitle":"Travel","breadcrumb":"Travel › Entering a Scene, Hex or Room","url":"/mechanics/optional/travel/#entering-a-scene-hex-or-room","content":"When entering a new hex, scene or room you should always roll for an event and insights. Event: An event that occurs when entering the hex (rolled each time you enter) Rolled from event-type table (3d6) Insights: Quests and factions and various things advance through insights. Insights are generic and should be applied and decided as the play is resolved for the area.","description":"","headingLevel":2,"fileSlug":"travel"},{"title":"Hex Information","pageTitle":"Travel","breadcrumb":"Travel › Hex Information","url":"/mechanics/optional/travel/#hex-information","content":"Each hex contains the following information: Level: Determined by dice roll when entering the hex Based on the level of the hex you're leaving See Level Generation table above Terrain/District: The type of terrain (wilderness) or district (urban) Terrain examples: forest, plains, mountain, swamp, island, desert, wastelands, magiclands Fantasy district examples: central, market, residential, slums, garden, religious, trade, admin, scholar, entertainment, crafts, arcane, industrial, noble Modern district examples: high-class, financial, middle-class, park, medical-park, commercial, downtown, government, university, tech, warehouse, industrial Feature: Special feature of the hex (from random tables) May include difficulty notation: (Easy), (Rough), or (Dangerous) Difficulty affects movement cost (see Movement Costs below) Landmark: Special location or discovery in the hex (generated when the hex is first populated) Rolled from landmark-type table (3d6) Exits: List of all 6 adjacent hexes ","description":"","headingLevel":3,"fileSlug":"travel"},{"title":"Level Generation","pageTitle":"Travel","breadcrumb":"Travel › Level Generation","url":"/mechanics/optional/travel/#level-generation","content":"When entering a new hex, determine its level based on the level of the hex you're leaving: | Leaving Hex Level | Dice Formula | Level Range | | ----------------- | ------------ | ----------- | | 1-2 | 1d4+2 | 3-6 | | 3-4 | 1d6+2 | 3-8 | | 5-6 | 1d8+2 | 3-10 | | 7-10 | 1d10+2 | 3-10\\ | \\ If rolling 1d10+2 results in 11 or 12, the hex level is 10.","description":"","headingLevel":3,"fileSlug":"travel"},{"title":"Movement Costs","pageTitle":"Travel","breadcrumb":"Travel › Movement Costs","url":"/mechanics/optional/travel/#movement-costs","content":"Movement between hexes costs movement points based on terrain difficulty: | Terrain Difficulty | Movement Cost | | ------------------ | ------------- | | Easy | 1 point | | Rough | 2 points | | Dangerous | 3 points | The difficulty comes from the feature of the hex you're entering. If a feature includes \"(Easy)\", \"(Rough)\", or \"(Dangerous)\", that determines the movement cost.","description":"","headingLevel":3,"fileSlug":"travel"},{"title":"Rest Procedure","pageTitle":"Travel","breadcrumb":"Travel › Rest Procedure","url":"/mechanics/optional/travel/#rest-procedure","content":"A rest consists of a number of rounds equal to 1 plus the number of players. If you are out in the wilderness we highly advise that each character takes a watch as a downtime activity. Each party member can choose to do 2 downtime activities and get a full nights rest barring any interruptions. (In the wilderness, one downtime activity should be a watch). Determine how many times to roll for a random encounter using the following equation. \\# of rounds - \\# of player This should be at least 1, but if a player does not take a watch you may have more possibility of rolling an encounter. Roll on the appropriate Rest encounter table to determine what happens. If you are tracking resources, reduce your rations and water by one. | 2d6 | Wilderness Rest | Safe Zone | | ----- | -------------------------- | ------------------------ | | 1-5 | Nothing | Roll Safe Zone Encounter | | 6-10 | Roll Travel Type Encounter | Nothing | | 11-12 | Roll on Discovery Table | Roll on Discovery Table |","description":"","headingLevel":3,"fileSlug":"travel"},{"title":"Wealth","pageTitle":"Wealth","breadcrumb":"Wealth","url":"/mechanics/optional/wealth/","content":"Wealth is abstracted into categories. Your wealth is a measure of your your income. All characters start at a Wealth of 3 unless there are background contingencies set up to allow a higher or lower wealth status. At Character creation, a player may decide if they are living above or below their character wealth. When a player is living below their means ease any Wealth checks. When a player is living above their means hinder any Wealth checks. | Quality of Life | Bonus/Penalty | | --------------- | ------------- | | Above Means | -1 | | At Means | 0 | | Below Means | +1 | At the end of any quest/mission/arc a character may roll a wealth check hindered by one step to see if they increase their wealth. If successful the player should define how that happened. You may purchase any item without a roll if it is under you wealth value. To purchase something that is at or above your wealth value, you can make a Level 3 plus each level above your wealth value Wealth check. reduce your wealth b","description":"","headingLevel":1,"fileSlug":"wealth"},{"title":"Cost","pageTitle":"Wealth","breadcrumb":"Wealth › Cost","url":"/mechanics/optional/wealth/#cost","content":"Most items will have a Cost level and not an exact amount. You can use the chart below for real world (or from other sources) to determine what the items cost will be here. | Level | DC | Description | Dollars/Credits | Gold/Other | | ----- | --- | ------------------------- | --------------------- | ----------------------- | | 0 | 0 | Free | $0 | 0 gold | | 1 | 3 | Inexpensive | $0 - $100 | 0 - 10 gold | | 2 | 6 | Moderate | $101 - $1,000 | 11 - 100 gold | | 3 | 9 | Expensive | $1,001 - $10,000 | 101 - 1,000 gold | | 4 | 12 | Very Expensive | $10,001 - $100,000 | 1,001 - 10,000 gold | | 5 | 15 | Exorbitant | $100,001 - $1,000,000 | 10,001 - 100,000 gold | | 6 | 18 | Priceless / Irreplaceable | $1,000,001+ | 100,001+ gold or Unique | You want to purchase a new fangled smartphone. A smart phone is an Expensive item and your wealth is 3. So you need to roll to see if you can successfully purchase it. You roll against a level 3 plus zero since it is not above your wealth score. Rolling a 1","description":"","headingLevel":2,"fileSlug":"wealth"},{"title":"Income","pageTitle":"Wealth","breadcrumb":"Wealth › Income","url":"/mechanics/optional/wealth/#income","content":"Every player character should have enough income to survive with their base expenses. Your income is your base Wealth value. For the most part the income shouldn't change unless there are in game reasons for it to do so.","description":"","headingLevel":2,"fileSlug":"wealth"},{"title":"Privacy Policy","pageTitle":"Privacy Policy","breadcrumb":"Privacy Policy","url":"/privacy-policy/","content":"(last updated: 2026-01-06) Tag and Tally respects your privacy. This Privacy Policy explains how information is handled when you use our documentation, app, or Discord bot (collectively, the “Services”).","description":"","headingLevel":1,"fileSlug":"privacy-policy"},{"title":"1. Data We Do **Not** Collect","pageTitle":"Privacy Policy","breadcrumb":"Privacy Policy › 1. Data We Do **Not** Collect","url":"/privacy-policy/#1-data-we-do-not-collect","content":"Tag and Tally does not: Collect personal information Store user data on our servers Track users across sessions or platforms Use analytics, tracking pixels, or advertising identifiers Sell, rent, or share user data Train AI or machine learning models on user content","description":"","headingLevel":3,"fileSlug":"privacy-policy"},{"title":"2. How Data Is Handled","pageTitle":"Privacy Policy","breadcrumb":"Privacy Policy › 2. How Data Is Handled","url":"/privacy-policy/#2-how-data-is-handled","content":"Any data created or used while interacting with Tag and Tally is handled in one of the following ways: Local Storage: Data may be stored locally in your browser or device storage. User-Controlled Cloud Storage: If enabled, data may be saved to cloud storage you explicitly authorize (for example, your own account or provider). At no point is this data transmitted to, stored on, or processed by Tag and Tally servers.","description":"","headingLevel":3,"fileSlug":"privacy-policy"},{"title":"3. Discord Bot Data","pageTitle":"Privacy Policy","breadcrumb":"Privacy Policy › 3. Discord Bot Data","url":"/privacy-policy/#3-discord-bot-data","content":"The Discord bot does not persistently store messages, user IDs, server IDs, or commands. All processing occurs in real time to respond to commands. No logs or historical records are retained by Tag and Tally. Discord itself may collect data independently under its own privacy policy.","description":"","headingLevel":3,"fileSlug":"privacy-policy"},{"title":"4. User-Generated Content","pageTitle":"Privacy Policy","breadcrumb":"Privacy Policy › 4. User-Generated Content","url":"/privacy-policy/#4-user-generated-content","content":"You retain full ownership of any content you create or submit. Tag and Tally does not archive, reuse, or analyze this content. Submitted content is not used for AI training, profiling, or data analysis.","description":"","headingLevel":3,"fileSlug":"privacy-policy"},{"title":"5. Third-Party Services","pageTitle":"Privacy Policy","breadcrumb":"Privacy Policy › 5. Third-Party Services","url":"/privacy-policy/#5-third-party-services","content":"Tag and Tally does not integrate third-party analytics, advertising, or data brokers. However, third-party platforms you use (such as Discord, browsers, or cloud storage providers) may collect data according to their own policies. Tag and Tally is not responsible for those practices.","description":"","headingLevel":3,"fileSlug":"privacy-policy"},{"title":"6. Children’s Privacy","pageTitle":"Privacy Policy","breadcrumb":"Privacy Policy › 6. Children’s Privacy","url":"/privacy-policy/#6-childrens-privacy","content":"Tag and Tally does not knowingly collect personal data from anyone, including children under 13. Because no personal data is collected, no age-based data processing occurs.","description":"","headingLevel":3,"fileSlug":"privacy-policy"},{"title":"7. Changes to This Policy","pageTitle":"Privacy Policy","breadcrumb":"Privacy Policy › 7. Changes to This Policy","url":"/privacy-policy/#7-changes-to-this-policy","content":"This Privacy Policy may be updated to reflect changes in the Services. Updates will be published alongside the documentation or app. Continued use indicates acceptance of the updated policy.","description":"","headingLevel":3,"fileSlug":"privacy-policy"},{"title":"8. Contact","pageTitle":"Privacy Policy","breadcrumb":"Privacy Policy › 8. Contact","url":"/privacy-policy/#8-contact","content":"For privacy-related questions or concerns, contact the project maintainer.","description":"","headingLevel":3,"fileSlug":"privacy-policy"},{"title":"Terms of Service","pageTitle":"Terms of Service","breadcrumb":"Terms of Service","url":"/terms-of-service/","content":"(last updated: 2026-01-06) By accessing or using the Tag and Tally documentation, Discord bot, or app (collectively, the “Services”), you agree to the following Terms of Service. If you do not agree, do not use the Services.","description":"","headingLevel":1,"fileSlug":"terms-of-service"},{"title":"1. License & Ownership","pageTitle":"Terms of Service","breadcrumb":"Terms of Service › 1. License & Ownership","url":"/terms-of-service/#1-license-ownership","content":"Tag and Tally © 2025 is licensed under Creative Commons Attribution-ShareAlike 4.0 International (CC BY-SA 4.0). You are free to: - Share — copy and redistribute the material - Adapt — remix, transform, and build upon the material Under the following conditions: - Attribution — You must give appropriate credit - ShareAlike — Any derivatives must use the same license Full license text is available at: https://creativecommons.org/licenses/by-sa/4.0/","description":"","headingLevel":3,"fileSlug":"terms-of-service"},{"title":"10. Contact","pageTitle":"Terms of Service","breadcrumb":"Terms of Service › 10. Contact","url":"/terms-of-service/#10-contact","content":"For questions, licensing clarification, or permissions beyond CC BY-SA 4.0, contact the project maintainer.","description":"","headingLevel":3,"fileSlug":"terms-of-service"},{"title":"2. What This License Covers","pageTitle":"Terms of Service","breadcrumb":"Terms of Service › 2. What This License Covers","url":"/terms-of-service/#2-what-this-license-covers","content":"The CC BY-SA 4.0 license applies to: Game rules and mechanics Written documentation Tables, tags, and system text Public-facing bot responses App content that reproduces system text The license does not grant ownership of the Tag and Tally name, logo, or branding.","description":"","headingLevel":3,"fileSlug":"terms-of-service"},{"title":"3. Trademarks & Branding","pageTitle":"Terms of Service","breadcrumb":"Terms of Service › 3. Trademarks & Branding","url":"/terms-of-service/#3-trademarks-branding","content":"“Tag and Tally” and associated logos or branding are not licensed under Creative Commons. You may reference the project by name for attribution or compatibility. You may not imply endorsement, sponsorship, or official status without permission.","description":"","headingLevel":3,"fileSlug":"terms-of-service"},{"title":"4. User-Generated Content","pageTitle":"Terms of Service","breadcrumb":"Terms of Service › 4. User-Generated Content","url":"/terms-of-service/#4-user-generated-content","content":"If you submit content through the Discord bot, app, or community spaces: You retain ownership of your content. You grant Tag and Tally a non-exclusive, royalty-free license to store, display, and process that content solely to operate the Services. You are responsible for ensuring your content does not violate laws or third-party rights.","description":"","headingLevel":3,"fileSlug":"terms-of-service"},{"title":"5. Acceptable Use","pageTitle":"Terms of Service","breadcrumb":"Terms of Service › 5. Acceptable Use","url":"/terms-of-service/#5-acceptable-use","content":"You agree not to: Use the Services for harassment, hate speech, or illegal activity Attempt to exploit, disrupt, or reverse-engineer the bot or app Misrepresent Tag and Tally content as proprietary or exclusively yours","description":"","headingLevel":3,"fileSlug":"terms-of-service"},{"title":"6. Availability & Changes","pageTitle":"Terms of Service","breadcrumb":"Terms of Service › 6. Availability & Changes","url":"/terms-of-service/#6-availability-changes","content":"The Services are provided “as is” with no guarantee of uptime or continued availability. Features, rules, or implementations may change at any time. Updates to these Terms may be made periodically; continued use constitutes acceptance.","description":"","headingLevel":3,"fileSlug":"terms-of-service"},{"title":"7. Disclaimer of Warranties","pageTitle":"Terms of Service","breadcrumb":"Terms of Service › 7. Disclaimer of Warranties","url":"/terms-of-service/#7-disclaimer-of-warranties","content":"The Services are provided without warranties of any kind, express or implied, including: Fitness for a particular purpose Accuracy or completeness Non-infringement Use at your own risk.","description":"","headingLevel":3,"fileSlug":"terms-of-service"},{"title":"8. Limitation of Liability","pageTitle":"Terms of Service","breadcrumb":"Terms of Service › 8. Limitation of Liability","url":"/terms-of-service/#8-limitation-of-liability","content":"To the maximum extent permitted by law: Tag and Tally shall not be liable for damages arising from use or inability to use the Services. This includes data loss, downtime, or gameplay disputes.","description":"","headingLevel":3,"fileSlug":"terms-of-service"},{"title":"9. Termination","pageTitle":"Terms of Service","breadcrumb":"Terms of Service › 9. Termination","url":"/terms-of-service/#9-termination","content":"Access to the Services may be suspended or terminated at any time for violations of these Terms or applicable laws.","description":"","headingLevel":3,"fileSlug":"terms-of-service"}];
